import { NextResponse } from "next/server";
import { headers } from "next/headers";
import { createSupabaseAdminClient } from "@/lib/supabase/admin";
import { toSafeErrorRecord } from "@/lib/logging/safe-error";

/**
 * POST /api/account/purge-deleted
 *
 * Permanently deletes user accounts whose soft-delete grace period has expired.
 * This endpoint should be called by a scheduled cron job (e.g. daily via Vercel
 * Cron, GitHub Actions, or a similar scheduler).
 *
 * Security: Requires a bearer token matching CRON_SECRET env var.
 */
export async function POST(request: Request) {
  const headerStore = await headers();
  const authHeader = headerStore.get("authorization") ?? "";
  const cronSecret = process.env.CRON_SECRET;

  // Guard: require a valid cron secret to prevent unauthorized purges
  if (!cronSecret || authHeader !== `Bearer ${cronSecret}`) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const admin = createSupabaseAdminClient();

  // List all users — Supabase admin listUsers paginates in batches of 1000
  // For a small/medium app this is fine; scale with cursor pagination if needed
  const { data: listData, error: listError } = await admin.auth.admin.listUsers({
    page: 1,
    perPage: 1000,
  });

  if (listError) {
    console.error("Failed to list users for purge", toSafeErrorRecord(listError));
    return NextResponse.json({ error: "Failed to list users" }, { status: 500 });
  }

  const now = new Date();
  const purged: string[] = [];
  const errors: string[] = [];

  for (const user of listData.users) {
    const meta = user.user_metadata;
    if (!meta?.deleted_at || !meta?.scheduled_purge_at) continue;

    const purgeAt = new Date(meta.scheduled_purge_at as string);
    if (purgeAt > now) continue; // Grace period not yet expired

    // Permanently delete the user
    const { error } = await admin.auth.admin.deleteUser(user.id, false);
    if (error) {
      console.error(`Failed to purge user ${user.id}`, toSafeErrorRecord(error));
      errors.push(user.id);
    } else {
      purged.push(user.id);
    }
  }

  return NextResponse.json({
    purgedCount: purged.length,
    errorCount: errors.length,
    purgedUserIds: purged,
    ...(errors.length > 0 ? { failedUserIds: errors } : {}),
  });
}

"use client";

import AchievementToast from "@/components/experience/AchievementToast";
import JuicyLevelCard from "@/components/experience/JuicyLevelCard";
import JuicyTabBar from "@/components/experience/JuicyTabBar";
import PhysicalButton from "@/components/experience/PhysicalButton";
import MascotHost from "@/components/experience/MascotHost";
import JuicyConfetti from "@/components/experience/JuicyConfetti";
import JuicyStreak from "@/components/experience/JuicyStreak";
import MascotFriend from "@/components/experience/KoydoMascotFriends";
import { useState } from "react";
import { Sparkles, Trophy, Rocket, Heart, Zap, Music, Palette, Leaf, Flame, Bell, Star } from "lucide-react";

type FriendId = "pixel" | "spark" | "echo" | "luna" | "terra";

export default function ExperiencePlayground() {
    const [activeTab, setActiveTab] = useState<"visuals" | "feedback" | "mascot">("visuals");
    const [showConfetti, setShowConfetti] = useState(false);
    const [streakCount, setStreakCount] = useState(0);
    const [selectedFriend, setSelectedFriend] = useState<FriendId>("pixel");
    const [toast, setToast] = useState<{ show: boolean; title: string; description: string; type: "achievement" | "level-up" | "streak" } | null>(null);

    const triggerConfetti = () => {
        setShowConfetti(true);
        setTimeout(() => setShowConfetti(false), 3000);
    };

    const triggerToast = (type: "achievement" | "level-up" | "streak") => {
        const titles = {
            achievement: "Collector Status!",
            "level-up": "Mastery Level 13",
            streak: "Unstoppable!"
        };
        const descriptions = {
            achievement: "You've earned the 'Alpha Catcher' badge!",
            "level-up": "You've unlocked the Galactic Map!",
            streak: "A perfect 10-answer run. Incredible!"
        };
        setToast({
            show: true,
            title: titles[type],
            description: descriptions[type],
            type
        });
    };

    return (
        <MascotHost initialMood="happy" friendId={selectedFriend}>
            <div className="space-y-12 py-10 min-h-screen pb-32">
                <header className="text-center space-y-4">
                    <h1 className="text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-sky-600 via-indigo-600 to-purple-600">
                        2026 Experience Playground
                    </h1>
                    <p className="text-stone-500 text-xl font-medium max-w-2xl mx-auto">
                        A universe of delight, materiality, and emotional intelligence.
                    </p>
                </header>

                <JuicyTabBar
                    ariaLabel="Playground sections"
                    value={activeTab}
                    tabs={[
                        { id: "visuals", label: "Visual Mastery" },
                        { id: "feedback", label: "Juicy Feedback" },
                        { id: "mascot", label: "Galaxy of Friends" },
                    ]}
                    onChange={setActiveTab}
                    className="max-w-md mx-auto"
                />

                {activeTab === "visuals" && (
                    <div className="grid gap-8 max-w-4xl mx-auto px-4">
                        <JuicyLevelCard level={12} xp={850} maxXp={1000} userName="Koydo Star" friendId={selectedFriend} />

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="p-8 rounded-[2.5rem] bg-indigo-50 dark:bg-indigo-950/30 border-2 border-indigo-100 dark:border-indigo-900 shadow-sm relative overflow-hidden group">
                                <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                                    <Rocket size={80} />
                                </div>
                                <h3 className="text-xl font-bold text-indigo-900 dark:text-indigo-300 mb-4">Glassmorphism UI</h3>
                                <p className="text-stone-600 dark:text-stone-400 leading-relaxed">
                                    Depth, transparency, and background blurs create a premium, high-focus environment that feels clean yet playful.
                                </p>
                            </div>
                            <div className="p-8 rounded-[2.5rem] bg-amber-50 dark:bg-amber-950/30 border-2 border-amber-100 dark:border-amber-900 shadow-sm relative overflow-hidden group">
                                <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                                    <Zap size={80} />
                                </div>
                                <h3 className="text-xl font-bold text-amber-900 dark:text-amber-300 mb-4">Materiality</h3>
                                <p className="text-stone-600 dark:text-stone-400 leading-relaxed">
                                    Every interaction has physics-based weight, squash, and stretch, bridging the gap between digital and physical toys.
                                </p>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === "feedback" && (
                    <div className="max-w-4xl mx-auto px-4 space-y-12">
                        <div className="flex flex-wrap justify-center gap-6 py-4">
                            <PhysicalButton onClick={triggerConfetti} variant="primary">
                                <Trophy className="h-6 w-6" />
                                Celebrate Achievement
                            </PhysicalButton>

                            <PhysicalButton onClick={() => triggerToast("achievement")} variant="primary">
                                <Bell className="h-6 w-6" />
                                Achievement Popup
                            </PhysicalButton>

                            <PhysicalButton onClick={() => triggerToast("level-up")} variant="primary" className="from-purple-500 to-indigo-600">
                                <Star className="h-6 w-6" />
                                Level Up Popup
                            </PhysicalButton>

                            <PhysicalButton onClick={() => setStreakCount(s => s + 1)} variant="success">
                                <Zap className="h-6 w-6" />
                                Correct Answer (+ Streak)
                            </PhysicalButton>

                            <PhysicalButton onClick={() => setStreakCount(0)} variant="danger">
                                <Flame className="h-6 w-6" />
                                Reset Streak
                            </PhysicalButton>
                        </div>

                        <div className="flex flex-col items-center gap-6 p-12 rounded-[3.5rem] bg-stone-50 dark:bg-stone-900/50 border-2 border-stone-100 dark:border-stone-800">
                            <h3 className="text-2xl font-black text-stone-800 dark:text-stone-100 italic">Combo System</h3>
                            <JuicyStreak count={streakCount} />
                            <p className="text-stone-500 font-medium">Get multiple correct answers to ignite the streak!</p>
                        </div>

                        <JuicyConfetti active={showConfetti} durationMs={3000} />
                    </div>
                )}

                {activeTab === "mascot" && (
                    <div className="max-w-5xl mx-auto px-4 space-y-12 text-center">
                        <div className="grid grid-cols-2 md:grid-cols-5 gap-6">
                            {(["pixel", "spark", "echo", "luna", "terra"] as const).map((fid) => (
                                <button
                                    key={fid}
                                    onClick={() => setSelectedFriend(fid)}
                                    className={`p-6 rounded-[2.5rem] border-2 transition-all space-y-4 hover:scale-105 ${selectedFriend === fid
                                        ? "bg-white dark:bg-stone-800 border-indigo-500 shadow-xl scale-110"
                                        : "bg-stone-50 dark:bg-stone-900 border-stone-200 dark:border-stone-800 grayscale hover:grayscale-0 opacity-60"
                                        }`}
                                >
                                    <MascotFriend id={fid} size={80} />
                                    <p className="font-black capitalize">{fid}</p>
                                    <div className="text-[10px] uppercase tracking-widest font-bold opacity-50">
                                        {fid === "pixel" && "General"}
                                        {fid === "spark" && "Math"}
                                        {fid === "echo" && "Phonics"}
                                        {fid === "luna" && "Creativity"}
                                        {fid === "terra" && "Science"}
                                    </div>
                                </button>
                            ))}
                        </div>

                        <div className="p-12 rounded-[3.5rem] bg-white dark:bg-stone-900 shadow-2xl border-2 border-stone-50 dark:border-stone-800 mt-8">
                            <h3 className="text-3xl font-black mb-6">World Integration</h3>
                            <p className="max-w-2xl mx-auto text-stone-600 dark:text-stone-400 text-lg leading-relaxed">
                                In 2026, the mascot isn&apos;t just a static SVG. It&apos;s a **context-aware companion**.
                                Taking a math lesson? **Spark** flies in. Working on art? **Luna** appears to guide your creativity.
                            </p>
                        </div>
                    </div>
                )}

                {toast && (
                    <AchievementToast
                        show={toast.show}
                        title={toast.title}
                        description={toast.description}
                        type={toast.type}
                        onClose={() => setToast(null)}
                    />
                )}
            </div>
        </MascotHost>
    );
}

"use client";

import { useEffect, useCallback } from "react";
import { initMixpanel } from "@/lib/analytics/mixpanel";
import { isAnalyticsAllowed, getConsentState } from "@/lib/consent/tracking-consent";
import {
  deleteSyncedProgress,
  getUnsyncedProgress,
} from "@/lib/offline/progress-db";

type AuthContextPayload = {
  isAuthenticated?: boolean;
};

async function isUserAuthenticated(): Promise<boolean> {
  try {
    const response = await fetch("/api/auth/context", { method: "GET" });
    if (!response.ok) {
      return false;
    }
    const payload = (await response.json()) as AuthContextPayload;
    return Boolean(payload.isAuthenticated);
  } catch {
    return false;
  }
}

async function syncOfflineProgress() {
  console.debug("Checking for offline progress to sync...");
  const unsynced = await getUnsyncedProgress();
  if (unsynced.length === 0) {
    console.debug("No offline progress to sync.");
    return;
  }

  const authenticated = await isUserAuthenticated();
  if (!authenticated) {
    // Expected for signed-out users; keep records for later authenticated sync.
    console.debug("Offline progress sync skipped: user is not authenticated.");
    return;
  }

  console.debug(`Found ${unsynced.length} records to sync.`);
  for (const record of unsynced) {
    try {
      const response = await fetch("/api/progress", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          lessonId: record.lessonId,
          scorePercentage: record.totalQuestions > 0 ? record.score / record.totalQuestions : 0,
        }),
      });

      if (response.ok) {
        await deleteSyncedProgress(record.lessonId);
        console.debug(`Record ${record.lessonId} synced successfully.`);
      } else if (response.status === 401 || response.status === 403) {
        // Session may have expired between checks; stop and retry on next cycle.
        console.debug("Offline progress sync paused: authentication required.");
        break;
      } else if (response.status === 400 || response.status === 422) {
        // Drop invalid payload rows so one bad entry cannot block the queue forever.
        await deleteSyncedProgress(record.lessonId);
        console.warn(
          `Dropped invalid offline progress ${record.lessonId}. Server responded with ${response.status}.`,
        );
      } else if (response.status === 429 || response.status >= 500) {
        console.warn(
          `Offline progress sync deferred after ${record.lessonId}. Server responded with ${response.status}.`,
        );
        // Stop trying on transient server/rate-limit errors to avoid server pressure.
        break;
      } else {
        console.warn(
          `Failed to sync record ${record.lessonId}. Server responded with ${response.status}.`,
        );
        break;
      }
    } catch (error) {
      console.error(`Error syncing record ${record.lessonId}:`, error);
      // Stop trying on the first error to avoid spamming the server if it's a persistent issue
      break;
    }
  }
}

export default function MixpanelProvider({
  children,
}: {
  children: React.ReactNode;
}) {
  const tryInitAnalytics = useCallback(() => {
    if (isAnalyticsAllowed()) {
      initMixpanel();
    }
  }, []);

  useEffect(() => {
    // Only initialize Mixpanel if the user has consented to analytics tracking.
    // On first visit, consent is undecided and analytics will NOT fire (GDPR default-deny).
    tryInitAnalytics();

    // Listen for consent updates (e.g., user clicks "Accept All" on banner)
    const handleConsentUpdate = () => {
      tryInitAnalytics();
    };
    window.addEventListener("koydo:consent-updated", handleConsentUpdate);

    // Set up background sync for offline progress (not gated by analytics consent)
    void syncOfflineProgress();
    const handleOnline = () => {
      void syncOfflineProgress();
    };
    window.addEventListener("online", handleOnline);

    return () => {
      window.removeEventListener("koydo:consent-updated", handleConsentUpdate);
      window.removeEventListener("online", handleOnline);
    };
  }, [tryInitAnalytics]);

  return <>{children}</>;
}

"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { BookOpen, Film, Clock, Sparkles, ArrowRight, ArrowLeft, Loader2 } from "lucide-react";
import { STORYFORGE_PRIORITY_QUEUE } from "@/lib/storyforge/types";
import { fetchGutenbergText } from "@/lib/storyforge/gutenberg-service";
import { decomposeTextToScenes } from "@/lib/storyforge/scene-decomposer";
import type { CinematicScene, StoryMetadata } from "@/lib/storyforge/types";
import StoryForgeCinemaViewer from "@/components/storyforge/StoryForgeCinemaViewer";

const TIER_LABELS = { A: "Short Film", B: "Chapter Film", C: "Feature", D: "Epic Series" };
const TIER_COLORS = { A: "emerald", B: "cyan", C: "violet", D: "amber" };

export default function StoryForgePage() {
  const [selectedStory, setSelectedStory] = useState<StoryMetadata | null>(null);
  const [scenes, setScenes] = useState<CinematicScene[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleLaunchFilm = async (story: StoryMetadata) => {
    if (!story.gutenbergId) return;

    setIsLoading(true);
    setError(null);

    try {
      const textResult = await fetchGutenbergText(story.gutenbergId);
      const decomposedScenes = decomposeTextToScenes(textResult.chapters);
      setScenes(decomposedScenes);
      setSelectedStory(story);
    } catch (err) {
      setError(`Failed to load "${story.title}". Please check your connection.`);
      console.error("[StoryForge] Ingestion error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  // If a story is playing, show the Cinema Viewer
  if (selectedStory && scenes.length > 0) {
    return (
      <div className="relative">
        <button
          onClick={() => { setSelectedStory(null); setScenes([]); }}
          className="fixed top-6 left-6 z-50 flex items-center gap-2 px-4 py-2 bg-white/5 backdrop-blur-xl border border-white/10 rounded-full text-white/60 hover:text-white hover:bg-white/10 transition text-sm"
        >
          <ArrowLeft className="w-4 h-4" /> Library
        </button>
        <StoryForgeCinemaViewer metadata={selectedStory} scenes={scenes} />
      </div>
    );
  }

  return (
    <main className="min-h-screen bg-gradient-to-br from-slate-950 via-indigo-950/30 to-slate-950 text-white">
      {/* Ambient Background */}
      <div className="fixed inset-0 pointer-events-none">
        <div className="absolute top-0 left-1/3 w-[600px] h-[600px] bg-violet-600/5 rounded-full blur-[150px]" />
        <div className="absolute bottom-0 right-1/4 w-[500px] h-[500px] bg-cyan-600/5 rounded-full blur-[120px]" />
      </div>

      {/* Header */}
      <header className="relative z-10 px-8 pt-16 pb-12 max-w-6xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="flex items-center gap-4 mb-4"
        >
          <div className="p-3 rounded-2xl bg-gradient-to-br from-violet-500/20 to-cyan-500/20 border border-white/10">
            <Film className="w-7 h-7 text-violet-300" />
          </div>
          <div>
            <h1 className="text-5xl font-black italic tracking-tighter">
              StoryForge{" "}
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-violet-400 to-cyan-400">
                Cinema
              </span>
            </h1>
            <p className="text-sm text-white/40 mt-1">
              Public domain literature transformed into immersive interactive films
            </p>
          </div>
        </motion.div>
      </header>

      {/* Error Banner */}
      <AnimatePresence>
        {error && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            className="relative z-10 mx-8 mb-6 max-w-6xl mx-auto bg-red-500/10 border border-red-500/20 rounded-2xl px-6 py-3 text-red-300 text-sm"
          >
            {error}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Loading Overlay */}
      <AnimatePresence>
        {isLoading && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 bg-black/80 backdrop-blur-xl flex flex-col items-center justify-center gap-4"
          >
            <Loader2 className="w-10 h-10 text-violet-400 animate-spin" />
            <p className="text-white/60 text-sm">Ingesting text from Project Gutenberg...</p>
            <p className="text-white/30 text-xs">Decomposing scenes & generating hotspots</p>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Film Library Grid */}
      <section className="relative z-10 px-8 max-w-6xl mx-auto">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {STORYFORGE_PRIORITY_QUEUE.map((story: StoryMetadata, index: number) => (
            <motion.div
              key={story.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.1 }}
              className="group relative bg-white/[0.03] backdrop-blur-xl border border-white/[0.06] rounded-3xl p-6 hover:bg-white/[0.06] hover:border-white/10 transition-all duration-500 cursor-pointer overflow-hidden"
              onClick={() => handleLaunchFilm(story)}
            >
              {/* Hover glow */}
              <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 bg-gradient-to-br from-violet-500/5 to-cyan-500/5 rounded-3xl" />

              <div className="relative z-10">
                {/* Tier Badge */}
                <div className="flex items-center justify-between mb-4">
                  <span className={`text-[10px] font-black uppercase tracking-[0.2em] px-3 py-1 rounded-full bg-white/5 border border-white/10 text-white/50`}>
                    {TIER_LABELS[story.contentTier]}
                  </span>
                  <span className="text-xs text-white/30 font-mono">
                    {story.year > 0 ? story.year : "Ancient"}
                  </span>
                </div>

                {/* Title */}
                <h3 className="text-xl font-bold tracking-tight text-white/90 mb-1 group-hover:text-white transition">
                  {story.title}
                </h3>
                <p className="text-sm text-white/40 mb-4">{story.author}</p>

                {/* Meta Row */}
                <div className="flex items-center gap-4 text-xs text-white/30">
                  <div className="flex items-center gap-1.5">
                    <Clock className="w-3.5 h-3.5" />
                    {story.estimatedDuration}
                  </div>
                  <div className="flex items-center gap-1.5">
                    <BookOpen className="w-3.5 h-3.5" />
                    Gutenberg #{story.gutenbergId}
                  </div>
                  <div className="flex items-center gap-1.5">
                    <Sparkles className="w-3.5 h-3.5" />
                    Interactive
                  </div>
                </div>

                {/* Launch Arrow */}
                <div className="mt-6 flex items-center gap-2 text-sm text-violet-400/60 group-hover:text-violet-300 transition">
                  <span>Launch Film</span>
                  <ArrowRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
                </div>
              </div>
            </motion.div>
          ))}
        </div>

        {/* Coming Soon Note */}
        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.8 }}
          className="text-center text-white/20 text-xs mt-12 pb-16"
        >
          More titles coming soon. The StoryForge pipeline can ingest any public-domain work from Project Gutenberg.
        </motion.p>
      </section>
    </main>
  );
}

"use client";

import { useState } from "react";
import type { CompanionGender } from "@/lib/greeter/companion-config";

interface CompanionAvatarSVGProps {
  gender: CompanionGender;
  size?: number;
  pulse?: boolean;
  className?: string;
  /**
   * When provided, renders a real photo <img> instead of the SVG cartoon.
   * Falls back to SVG on load error.
   */
  previewImageUrl?: string;
}

export default function CompanionAvatarSVG({
  gender,
  size = 48,
  pulse = false,
  className = "",
  previewImageUrl,
}: CompanionAvatarSVGProps) {
  const [imgFailed, setImgFailed] = useState(false);
  const showImg = previewImageUrl && !imgFailed;

  const pulseClass = pulse ? "animate-pulse" : "";
  const borderColor = gender === "female" ? "#7c3aed" : "#0891b2";
  const bgColor = gender === "female" ? "#ede9fe" : "#cffafe";

  if (showImg) {
    return (
      <img
        src={previewImageUrl}
        alt={gender === "female" ? "Aria" : "Kai"}
        width={size}
        height={size}
        className={`rounded-full object-cover ${pulseClass} ${className}`}
        style={{
          width: size,
          height: size,
          border: `2px solid ${borderColor}`,
        }}
        onError={() => setImgFailed(true)}
        draggable={false}
      />
    );
  }

  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 48 48"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden
      className={`select-none ${pulseClass} ${className}`}
      style={{ flexShrink: 0 }}
    >
      {/* Background circle */}
      <circle cx="24" cy="24" r="24" fill={bgColor} />

      {gender === "female" ? (
        /* Aria — warm violet cartoon */
        <>
          {/* Hair */}
          <ellipse cx="24" cy="16" rx="11" ry="9" fill="#4c1d95" />
          <ellipse cx="24" cy="23" rx="10" ry="5" fill="#4c1d95" opacity="0.6" />
          {/* Face */}
          <circle cx="24" cy="21" r="9" fill="#fde68a" />
          {/* Eyes */}
          <circle cx="21" cy="20" r="1.5" fill="#1f2937" />
          <circle cx="27" cy="20" r="1.5" fill="#1f2937" />
          <circle cx="21.5" cy="19.5" r="0.5" fill="white" />
          <circle cx="27.5" cy="19.5" r="0.5" fill="white" />
