}

function DeploymentButton({ label, desc, icon: Icon, color, active, onClick }: any) {
    return (
        <motion.button
            whileHover={{ x: 8 }}
            onClick={onClick}
            className={`group flex items-center gap-4 w-full p-4 rounded-3xl border transition-all text-left
