"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { Sun, CloudRain, Wind, TreePine, Bird, Waves, Thermometer, ShieldCheck, Activity, Info } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Ecosystem Types --- */
type Entity = "PLANNER" | "CONSUMER" | "DECOMPOSER";

export default function BiomeBuilder() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"IDLE" | "SIMULATING" | "COLLAPSE" | "STABLE">("IDLE");
    const [stats, setStats] = useState({
        flora: 50,
        fauna: 20,
        water: 60,
        temperature: 25
    });
    const [equilibrium, setEquilibrium] = useState(70);
    const [days, setDays] = useState(0);

    const runSimulation = useCallback(() => {
        if (gameState !== "SIMULATING") return;

        const interval = setInterval(() => {
            setStats(prev => {
                // Ecological logic
                const newFlora = prev.flora + (prev.water * 0.1) - (prev.fauna * 0.2) - (Math.abs(prev.temperature - 25) * 0.1);
                const newFauna = prev.fauna + (prev.flora * 0.05) - (prev.fauna * 0.05);
                const newWater = prev.water - (prev.flora * 0.02) - (prev.temperature * 0.01);

                return {
                    flora: Math.max(0, Math.min(100, newFlora)),
                    fauna: Math.max(0, Math.min(100, newFauna)),
                    water: Math.max(0, Math.min(100, newWater)),
                    temperature: prev.temperature // Controlled by user
                };
            });

            setDays(d => d + 1);
        }, 2000);

        return () => clearInterval(interval);
    }, [gameState]);

    useEffect(() => {
        runSimulation();
    }, [runSimulation]);

    // Stability Calculation
    useEffect(() => {
        const diff = Math.abs(stats.flora - 60) + Math.abs(stats.fauna - 40) + Math.abs(stats.water - 50);
        const stability = Math.max(0, 100 - diff);
        setEquilibrium(stability);

        if (stability < 20 && gameState === "SIMULATING") {
            setGameState("COLLAPSE");
            setMood("sad");
            setMessage("The ecosystem has collapsed. Biodiversity loss is critical. We must restart the cycle. 🥀");
            hapticError();
        } else if (days > 100 && stability > 80) {
            setGameState("STABLE");
            setMood("happy");
            setMessage("Incredible! You've achieved a self-sustaining Biome Equilibrium. 🌿");
            hapticSuccess();
        }
    }, [stats, days, gameState, setMood, setMessage]);

    const adjustStat = (key: keyof typeof stats, amount: number) => {
        setStats(prev => ({ ...prev, [key]: Math.max(0, Math.min(100, prev[key] + amount)) }));
        hapticSelection();
    };

    const startSim = () => {
        setGameState("SIMULATING");
        setDays(0);
        setMood("thinking");
        setMessage("Ecosystem initialization complete. Balance the flora, fauna, and resources to reach Equilibrium! 🌲");
        hapticSuccess();
    };

    return (
        <div className="relative w-full max-w-6xl mx-auto min-h-[700px] bg-emerald-950 rounded-[4rem] border border-emerald-500/20 overflow-hidden shadow-2xl flex flex-col font-sans">
            {/* 4K Environmental Background */}
            <div className="absolute inset-0 z-0">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_bottom,rgba(34,197,94,0.2)_0%,transparent_70%)]" />
                {/* Dynamic Weather Layer */}
                <motion.div
                    className="absolute inset-0 opacity-10"
                    animate={{ opacity: [0.1, 0.2, 0.1] }}
                    transition={{ duration: 10, repeat: Infinity }}
                    style={{ background: "radial-gradient(circle at 70% 20%, #fbbf24 0%, transparent 40%)" }}
                />
            </div>

            {/* Top Bar: Ecosystem HUD */}
            <div className="relative z-20 p-10 flex justify-between items-center bg-zinc-900/40 backdrop-blur-3xl border-b border-white/5">
                <div className="flex items-center gap-6">
                    <div className="w-16 h-16 rounded-3xl bg-emerald-500/20 border border-emerald-500/30 flex items-center justify-center">
                        <TreePine className="text-emerald-400 w-10 h-10" />
                    </div>
                    <div>
                        <h2 className="text-3xl font-black italic tracking-tighter text-white uppercase">Biome Builder</h2>
                        <div className="flex items-center gap-2">
                            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                            <span className="text-[10px] font-black text-emerald-500/80 uppercase tracking-[0.3em]">Biosphere Simulation Active</span>
                        </div>
                    </div>
                </div>

                <div className="flex gap-6">
                    <div className="bg-zinc-800/50 border border-white/5 px-8 py-4 rounded-[2rem] flex flex-col items-end">
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Ecosystem Stability</span>
                        <div className="flex items-baseline gap-2">
                            <span className="text-3xl font-black italic tabular-nums text-white">{equilibrium.toFixed(0)}%</span>
                            <Activity className={`w-4 h-4 ${equilibrium > 50 ? 'text-emerald-400' : 'text-rose-400'}`} />
                        </div>
                    </div>
                    <div className="bg-white/5 border border-white/10 px-8 py-4 rounded-[2rem] flex flex-col items-end min-w-[120px]">
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">Day Cycle</span>
                        <span className="text-3xl font-black italic tabular-nums text-white">{days}</span>
                    </div>
                </div>
            </div>

            {/* Main Simulation View */}
            <div className="relative z-10 flex-1 p-10 grid grid-cols-12 gap-10">
                {/* Left: Interactive Controls */}
                <div className="col-span-4 space-y-6">
                    <div className="bg-zinc-900/40 border border-white/5 p-8 rounded-[3rem] backdrop-blur-md">
                        <h3 className="text-sm font-black uppercase tracking-widest text-zinc-500 mb-6 flex items-center gap-2">
                            <Wind className="w-4 h-4" /> Resource Control
                        </h3>

                        <div className="space-y-8">
                            <ControlGroup
                                label="Precipitation"
                                icon={<CloudRain className="w-5 h-5 text-sky-400" />}
                                value={stats.water}
                                onAdjust={(v) => adjustStat("water", v)}
                            />
                            <ControlGroup
                                label="Thermodynamics"
                                icon={<Thermometer className="w-5 h-5 text-orange-400" />}
                                value={stats.temperature}
                                onAdjust={(v) => adjustStat("temperature", v)}
                            />
                        </div>
                    </div>

                    <div className="bg-emerald-500/10 border border-emerald-500/20 p-8 rounded-[3rem] backdrop-blur-md">
                        <div className="flex items-center gap-3 mb-4 text-emerald-400">
                            <Info className="w-5 h-5" />
                            <span className="text-[10px] font-black uppercase tracking-widest">Growth Forecast</span>
                        </div>
                        <p className="text-emerald-500/80 text-xs italic leading-relaxed">
                            {stats.water > 70 ? "High rainfall promotes flora expansion." :
                                stats.temperature > 30 ? "Heatwave causing water evaporation." :
                                    "Conditions stable for balanced growth."}
                        </p>
                    </div>
                </div>

                {/* Right: Visualization & Species */}
                <div className="col-span-8 space-y-8 flex flex-col">
                    <div className="flex-1 bg-zinc-900/40 border border-white/5 rounded-[4rem] relative overflow-hidden group">
                        {/* 4K Visualization Space (Illustrative Grid) */}
                        <div className="absolute inset-0 grid grid-cols-8 grid-rows-6 opacity-30 pointer-events-none">
                            {Array.from({ length: 48 }).map((_, i) => (
                                <div key={i} className="border-[0.5px] border-emerald-500/10" />
                            ))}
                        </div>

                        {/* Animated Species Clusters */}
                        <div className="absolute inset-10 flex items-center justify-center gap-20">
                            <SpeciesRadar label="Flora" value={stats.flora} color="#10b981" icon={<TreePine />} />
                            <SpeciesRadar label="Fauna" value={stats.fauna} color="#f59e0b" icon={<Bird />} />
                        </div>

                        {/* Status Overlay */}
                        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur-xl px-10 py-4 rounded-full border border-white/10 flex items-center gap-4">
                            <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest">Biome Status:</span>
                            <span className={`text-sm font-black italic ${equilibrium > 70 ? 'text-emerald-400' : 'text-orange-400'}`}>
                                {equilibrium > 80 ? "Sustaining" : equilibrium > 50 ? "Adapting" : "Stressed"}
                            </span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Overlays */}
            {(gameState === "IDLE" || gameState === "COLLAPSE" || gameState === "STABLE") && (
                <motion.div
                    {...JUICY_VARIANTS.slideUp}
                    className="absolute inset-0 z-40 bg-zinc-950/90 backdrop-blur-3xl flex flex-col items-center justify-center p-12 text-center"
                >
                    <div className={`w-24 h-24 rounded-[2.5rem] flex items-center justify-center border border-white/10 mb-8 overflow-hidden
                        ${gameState === "STABLE" ? 'bg-emerald-500/20 border-emerald-500/30' : 'bg-white/5'}`}>
                        <TreePine className={`w-12 h-12 ${gameState === "STABLE" ? 'text-emerald-400' : 'text-zinc-500'}`} />
                    </div>
                    <h3 className="text-5xl font-black italic tracking-tighter text-white mb-4 uppercase">
                        {gameState === "STABLE" ? "Equilibrium Reached" :
                            gameState === "COLLAPSE" ? "Ecosystem Failure" : "Initialize Biosphere"}
                    </h3>
                    <p className="text-zinc-500 text-sm max-w-sm mb-12 italic leading-relaxed">
                        Master the delicate balance between climate and life forms. Your choices determine the survival of this digital ecosystem.
                    </p>
                    <PhysicalButton
                        onClick={startSim}
                        className="bg-emerald-500 h-24 px-20 rounded-[3rem] text-2xl font-black italic"
                    >
                        {gameState === "COLLAPSE" ? "RESTART CYCLE 🔄" : "BEGIN SIMULATION 🌿"}
                    </PhysicalButton>
                </motion.div>
            )}
        </div>
    );
}

/* --- Sub-Components --- */

function ControlGroup({ label, icon, value, onAdjust }: { label: string, icon: any, value: number, onAdjust: (v: number) => void }) {
    return (
        <div className="space-y-4">
            <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                    {icon}
                    <span className="text-xs font-black text-white uppercase tracking-widest font-mono">{label}</span>
                </div>
                <span className="text-xl font-black italic text-zinc-400 tabular-nums">{value.toFixed(0)}%</span>
            </div>
            <div className="flex gap-2">
                <button
                    onClick={() => onAdjust(-5)}
                    className="flex-1 h-12 bg-zinc-800 border border-white/5 rounded-xl text-white font-black hover:bg-zinc-700 active:scale-95 transition-all"
                >
                    -
                </button>
                <button
                    onClick={() => onAdjust(5)}
                    className="flex-1 h-12 bg-zinc-800 border border-white/5 rounded-xl text-white font-black hover:bg-zinc-700 active:scale-95 transition-all"
                >
                    +
                </button>
            </div>
            <div className="w-full h-1 bg-white/5 rounded-full overflow-hidden">
                <motion.div className="h-full bg-emerald-500" animate={{ width: `${value}%` }} />
            </div>
        </div>
    );
}

function SpeciesRadar({ label, value, color, icon }: { label: string, value: number, color: string, icon: any }) {
    return (
        <div className="flex flex-col items-center gap-4">
            <div className="relative w-40 h-40 flex items-center justify-center">
                <motion.div
                    className="absolute inset-0 rounded-full border-2 border-dashed opacity-20"
                    style={{ borderColor: color }}
                    animate={{ rotate: 360 }}
                    transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
                />
                <motion.div
                    className="rounded-full shadow-2xl flex items-center justify-center"
                    style={{
                        width: `${Math.max(40, value * 1.4)}px`,
                        height: `${Math.max(40, value * 1.4)}px`,
                        backgroundColor: `${color}20`,
                        border: `2px solid ${color}40`
                    }}
                >
                    <div style={{ color }}>{icon}</div>
                </motion.div>
            </div>
            <span className="text-xs font-black uppercase tracking-widest text-zinc-500">{label}</span>
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { Cpu, Play, Square, RotateCcw, Code, Zap, Settings, Activity, ShieldCheck, ChevronRight, Terminal, Bot } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Programming Types --- */
type Command = "MOVE_FORWARD" | "TURN_LEFT" | "TURN_RIGHT" | "REPEAT_2" | "COLLECT";

type BotState = {
    x: number;
    y: number;
    dir: 0 | 90 | 180 | 270; // Degrees
    inventory: number;
};

const COMMAND_DATA: Record<Command, { label: string, icon: any, color: string }> = {
    MOVE_FORWARD: { label: "Move Forward", icon: ChevronRight, color: "bg-blue-500" },
    TURN_LEFT: { label: "Turn Left", icon: RotateCcw, color: "bg-purple-500" },
    TURN_RIGHT: { label: "Turn Right", icon: RotateCcw, color: "bg-indigo-500" },
    REPEAT_2: { label: "Repeat 2x", icon: Zap, color: "bg-amber-500" },
    COLLECT: { label: "Collect Data", icon: ShieldCheck, color: "bg-emerald-500" }
};

export default function BotBuilder() {
    const { setMessage, setMood } = useMascot();
    const [program, setProgram] = useState<Command[]>([]);
    const [bot, setBot] = useState<BotState>({ x: 0, y: 0, dir: 0, inventory: 0 });
    const [isRunning, setIsRunning] = useState(false);
    const [execIndex, setExecIndex] = useState(-1);
    const [gridSize] = useState(5);
    const [target] = useState({ x: 3, y: 3 });

    // Reset simulation
    const resetBot = useCallback(() => {
        setBot({ x: 0, y: 0, dir: 0, inventory: 0 });
        setIsRunning(false);
        setExecIndex(-1);
    }, []);

    const runProgram = async () => {
        if (program.length === 0) {
            setMessage("We need some code to run the bot! 🤖");
            hapticError();
            return;
        }

        setIsRunning(true);
        setMessage("Executing sequence... watching logic loops in real-time. ⚡");
        setMood("thinking");
        hapticSelection();

        let currentBot = { ...bot };

        for (let i = 0; i < program.length; i++) {
            setExecIndex(i);
            const cmd = program[i];

            // Logic implementation
            if (cmd === "MOVE_FORWARD") {
                if (currentBot.dir === 0) currentBot.x = Math.min(gridSize - 1, currentBot.x + 1);
                if (currentBot.dir === 90) currentBot.y = Math.min(gridSize - 1, currentBot.y + 1);
                if (currentBot.dir === 180) currentBot.x = Math.max(0, currentBot.x - 1);
                if (currentBot.dir === 270) currentBot.y = Math.max(0, currentBot.y - 1);
            } else if (cmd === "TURN_LEFT") {
                currentBot.dir = (currentBot.dir + 270) % 360 as any;
            } else if (cmd === "TURN_RIGHT") {
                currentBot.dir = (currentBot.dir + 90) % 360 as any;
            } else if (cmd === "COLLECT") {
                if (currentBot.x === target.x && currentBot.y === target.y) {
                    currentBot.inventory += 1;
                }
            }

            setBot({ ...currentBot });
            await new Promise(r => setTimeout(r, 600));
        }

        setIsRunning(false);
        setExecIndex(-1);

        if (currentBot.inventory > 0) {
            setMessage("Sequence complete! Data package secured. Great coding! 🌟");
            setMood("happy");
            hapticSuccess();
        } else {
            setMessage("Sequence finished, but we missed the target. Debug and try again! 🔧");
            setMood("sad");
            hapticError();
        }
    };

    const addCommand = (cmd: Command) => {
        if (program.length < 8) {
            setProgram(prev => [...prev, cmd]);
            hapticSelection();
        } else {
            hapticError();
        }
    };

    const clearProgram = () => {
        setProgram([]);
        resetBot();
        hapticSelection();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[700px] bg-zinc-950 rounded-[4rem] border border-blue-500/20 overflow-hidden shadow-2xl flex flex-col font-sans">
            {/* Terminal Background */}
            <div className="absolute inset-0 z-0 opacity-10 pointer-events-none">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(59,130,246,0.1)_0%,transparent_70%)]" />
                <svg className="absolute inset-0 w-full h-full text-blue-500/5">
                    <pattern id="grid" x="0" y="0" width="40" height="40" patternUnits="userSpaceOnUse">
                        <path d="M 40 0 L 0 0 0 40" fill="none" stroke="currentColor" strokeWidth="1" />
                    </pattern>
                    <rect width="100%" height="100%" fill="url(#grid)" />
                </svg>
            </div>

            {/* HUD */}
            <div className="relative z-20 p-8 flex justify-between items-center bg-zinc-900/60 backdrop-blur-2xl border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-2xl bg-blue-500/10 border border-blue-500/30 flex items-center justify-center">
                        <Bot className="text-blue-400 w-8 h-8" />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black italic tracking-tighter text-white uppercase leading-none">Bot Builder</h2>
                        <span className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">Automation Engine v1.0</span>
                    </div>
                </div>

                <div className="flex gap-4">
                    <PhysicalButton
                        onClick={program.length > 0 && !isRunning ? runProgram : undefined}
                        className={`h-14 px-8 rounded-2xl text-sm ${isRunning ? 'bg-zinc-800 opacity-50' : 'bg-blue-600'}`}
                    >
                        {isRunning ? <Settings className="animate-spin w-4 h-4" /> : <Play className="w-4 h-4 fill-current mr-2" />}
                        {isRunning ? "RUNNING..." : "EXECUTE CODE"}
                    </PhysicalButton>
                    <PhysicalButton
                        onClick={clearProgram}
                        className="bg-zinc-800 h-14 w-14 rounded-2xl flex items-center justify-center"
                    >
                        <RotateCcw className="w-4 h-4" />
                    </PhysicalButton>
                </div>
            </div>

            {/* IDE Workspace */}
            <div className="relative z-10 flex-1 flex overflow-hidden">
                {/* Left: Command Palette */}
                <div className="w-72 border-r border-white/5 p-6 flex flex-col gap-3 bg-zinc-900/40">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-2 flex items-center gap-2">
                        <Code className="w-3 h-3" /> Instruction Set
                    </h3>
                    {(Object.keys(COMMAND_DATA) as Command[]).map(cmd => (
                        <CommandButton
                            key={cmd}
                            cmd={cmd}
                            onClick={() => addCommand(cmd)}
                            disabled={isRunning}
                        />
                    ))}
                </div>

                {/* Center: Logic Stream */}
                <div className="flex-1 p-8 flex flex-col bg-zinc-950/20">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-6 flex items-center gap-2">
                        <Terminal className="w-3 h-3" /> Main Execution Loop
                    </h3>
                    <div className="flex flex-col gap-2">
                        <AnimatePresence>
                            {program.length === 0 ? (
                                <motion.div
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 1 }}
                                    className="h-40 border-2 border-dashed border-white/5 rounded-3xl flex items-center justify-center italic text-zinc-700 text-sm"
                                >
                                    Drag commands here to start building...
                                </motion.div>
                            ) : (
                                program.map((cmd, idx) => (
                                    <motion.div
                                        key={idx}
                                        initial={{ x: -20, opacity: 0 }}
                                        animate={{ x: 0, opacity: 1 }}
                                        className={`flex items-center justify-between p-4 rounded-2xl border transition-all duration-300
                                            ${execIndex === idx ? 'bg-blue-500/20 border-blue-500 shadow-[0_0_20px_rgba(59,130,246,0.2)]' : 'bg-white/5 border-white/5'}`}
                                    >
                                        <div className="flex items-center gap-3">
                                            <span className="text-[10px] font-mono text-zinc-600 w-4">{idx + 1}</span>
                                            <div className={`w-8 h-8 rounded-lg ${COMMAND_DATA[cmd].color} flex items-center justify-center`}>
                                                <CommandIcon cmd={cmd} />
                                            </div>
                                            <span className={`text-sm font-bold ${execIndex === idx ? 'text-white' : 'text-zinc-400'}`}>
                                                {COMMAND_DATA[cmd].label}
                                            </span>
                                        </div>
                                        {execIndex === idx && <Activity className="w-4 h-4 text-blue-400 animate-pulse" />}
                                    </motion.div>
                                ))
                            )}
                        </AnimatePresence>
                    </div>
                </div>

                {/* Right: Simulation Grid */}
                <div className="w-80 border-l border-white/5 p-8 flex flex-col items-center justify-center bg-zinc-900/60">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-8">Visualizer</h3>
                    <div className="relative w-64 h-64 grid grid-cols-5 grid-rows-5 gap-1 bg-black/40 rounded-2xl p-2 border border-white/5 shadow-inner">
                        {Array.from({ length: 25 }).map((_, i) => {
                            const x = i % 5;
                            const y = Math.floor(i / 5);
                            const isTarget = x === target.x && y === target.y;
                            return (
                                <div key={i} className="relative bg-white/5 rounded-sm border border-white/5">
                                    {isTarget && (
                                        <motion.div
                                            animate={{ scale: [1, 1.2, 1] }}
                                            transition={{ duration: 2, repeat: Infinity }}
                                            className="absolute inset-1 bg-emerald-500/20 rounded-sm flex items-center justify-center"
                                        >
                                            <ShieldCheck className="w-4 h-4 text-emerald-400" />
                                        </motion.div>
                                    )}
                                </div>
                            );
                        })}

                        {/* The Bot */}
                        <motion.div
                            className="absolute bg-blue-500 rounded-xl shadow-[0_0_20px_rgba(59,130,246,0.5)] flex items-center justify-center"
                            animate={{
                                left: `${bot.x * (64 / 5) * 4}px`,
                                top: `${bot.y * (64 / 5) * 4}px`,
                                rotate: bot.dir
                            }}
                            style={{ width: '48px', height: '48px', margin: '4px' }}
                        >
                            <Bot className="w-8 h-8 text-white" />
                        </motion.div>
                    </div>

                    <div className="mt-8 flex flex-col gap-4 w-full">
                        <StatRow label="Inventory" value={bot.inventory} icon={ShieldCheck} color="text-emerald-400" />
                        <StatRow label="CPU Cycles" value={execIndex + 1} icon={Cpu} color="text-blue-400" />
                    </div>
                </div>
            </div>
        </div>
    );
}

function CommandButton({ cmd, onClick, disabled }: { cmd: Command, onClick: () => void, disabled?: boolean }) {
    const data = COMMAND_DATA[cmd];
    const Icon = data.icon;

    return (
        <button
            onClick={onClick}
            disabled={disabled}
            className="group flex items-center gap-3 p-4 rounded-2xl bg-white/5 border border-white/5 hover:bg-zinc-800 hover:border-blue-500/30 transition-all text-left disabled:opacity-30 disabled:pointer-events-none"
        >
            <div className={`w-10 h-10 rounded-xl ${data.color} flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform`}>
                <CommandIcon cmd={cmd} />
            </div>
            <span className="text-sm font-bold text-zinc-300 group-hover:text-white">{data.label}</span>
        </button>
    );
}

function CommandIcon({ cmd }: { cmd: Command }) {
    const data = COMMAND_DATA[cmd];
    const Icon = data.icon;
    return <Icon className="w-5 h-5 text-white" />;
}

function StatRow({ label, value, icon: Icon, color }: { label: string, value: any, icon: any, color: string }) {
    return (
        <div className="flex justify-between items-center bg-white/5 p-4 rounded-2xl border border-white/5">
            <div className="flex items-center gap-2">
                <Icon className={`w-3 h-3 ${color}`} />
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">{label}</span>
            </div>
            <span className="text-sm font-black text-white">{value}</span>
        </div>
    );
}

"use client";

import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
    Search,
    Clock,
    BookOpen,
    Shield,
    CheckCircle2,
    AlertCircle,
    RotateCcw,
    Zap,
    Map
} from "lucide-react";
import {
    JUICY_SPRINGS,
    JUICY_VARIANTS
} from "@/lib/experience/interaction-primitives";
import PhysicalButton from "@/components/experience/PhysicalButton";
import JuicyStreak from "@/components/experience/JuicyStreak";
import JuicyConfetti from "@/components/experience/JuicyConfetti";
import { hapticSuccess, hapticError, hapticSelection } from "@/lib/platform/haptics";
import { useMascot } from "@/components/experience/MascotHost";

// 4K Noir Color Palette
const NOIR_COLORS = {
    bg: "bg-[#0a0a0c]",
    glass: "bg-white/5 backdrop-blur-2xl border-white/10",
    accent: "text-amber-400",
    accentBg: "bg-amber-400/20",
    accentBorder: "border-amber-400/30",
    dim: "text-slate-500",
    bright: "text-white"
};

interface Clue {
    id: string;
    name: string;
    description: string;
    year: number;
    found: boolean;
    x: number; // Percent
    y: number; // Percent
    category: "artifact" | "document" | "tool";
}

const HISTORICAL_CASES = [
    {
        id: "case-1",
        title: "The Lost Library of Alexandria",
        era: "Ancient World",
        clues: [
            { id: "c1", name: "Papyrus Fragment", description: "A fragment of a scroll detailing celestial movements.", year: -300, found: false, x: 20, y: 30, category: "document" },
            { id: "c2", name: "Bronze Astrolabe", description: "An ancient tool for navigating by the stars.", year: -150, found: false, x: 70, y: 20, category: "tool" },
            { id: "c3", name: "Limestone Relief", description: "Depicts a scholar teaching students in a great hall.", year: -250, found: false, x: 45, y: 75, category: "artifact" },
        ]
    },
    {
        id: "case-2",
        title: "The Renaissance Workshop",
        era: "15th Century",
        clues: [
            { id: "c1", name: "Drafting Compass", description: "Used for precise anatomical sketches.", year: 1480, found: false, x: 15, y: 40, category: "tool" },
            { id: "c2", name: "Silver Denarius", description: "Currency from a forgotten trade route.", year: 1492, found: false, x: 80, y: 60, category: "artifact" },
            { id: "c3", name: "Codex Page", description: "Mirror-written notes on flying machines.", year: 1505, found: false, x: 55, y: 15, category: "document" },
        ]
    }
];

export default function ChronicleCase() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"briefing" | "investigation" | "deduction" | "solved">("briefing");
    const [currentCaseIndex, setCurrentCaseIndex] = useState(0);
    const [clues, setClues] = useState<Clue[]>([]);
    const [foundCount, setFoundCount] = useState(0);
    const [timeline, setTimeline] = useState<Clue[]>([]);
    const [showConfetti, setShowConfetti] = useState(false);
    const [searchPos, setSearchPos] = useState({ x: 50, y: 50 });
    const containerRef = useRef<HTMLDivElement>(null);

    const currentCase = HISTORICAL_CASES[currentCaseIndex];

    useEffect(() => {
        setClues(currentCase.clues.map(c => ({ ...c })) as Clue[]);
    }, [currentCaseIndex, currentCase.clues]);

    const startInvestigation = () => {
        setGameState("investigation");
        setMessage(`Attention, Investigator. We need to recover ${currentCase.clues.length} temporal fragments from ${currentCase.era}. Search the area carefully.`);
        setMood("thinking");
        hapticSelection();
    };

    const handleSearch = (e: React.MouseEvent | React.TouchEvent) => {
        if (gameState !== "investigation") return;

        const rect = containerRef.current?.getBoundingClientRect();
        if (!rect) return;

        const clientX = (e as any).touches ? (e as any).touches[0].clientX : (e as React.MouseEvent).clientX;
        const clientY = (e as any).touches ? (e as any).touches[0].clientY : (e as React.MouseEvent).clientY;

        const x = ((clientX - rect.left) / rect.width) * 100;
        const y = ((clientY - rect.top) / rect.height) * 100;

        setSearchPos({ x, y });

        // Check for clue hits
        clues.forEach((clue, idx) => {
            if (!clue.found) {
                const dist = Math.sqrt(Math.pow(x - clue.x, 2) + Math.pow(y - clue.y, 2));
                if (dist < 8) { // Hit threshold
                    const updatedClues = [...clues];
                    updatedClues[idx].found = true;
                    setClues(updatedClues);
                    setFoundCount(prev => prev + 1);
                    hapticSuccess();
                    setMessage(`Excellent. Found the ${clue.name}. It dates back to ${Math.abs(clue.year)} ${clue.year < 0 ? 'BCE' : 'CE'}.`);

                    if (foundCount + 1 === clues.length) {
                        setTimeout(() => {
                            setGameState("deduction");
                            setMessage("All clues recovered. Now, reconstruct the timeline to stabilize the narrative.");
                        }, 1500);
                    }
                }
            }
        });
    };

    const addToTimeline = (clue: Clue) => {
        if (timeline.find(c => c.id === clue.id)) return;
        setTimeline([...timeline, clue]);
        hapticSelection();
    };

    const checkTimeline = () => {
        const isCorrect = timeline.every((clue, idx) => {
            if (idx === 0) return true;
            return clue.year >= timeline[idx - 1].year;
        }) && timeline.length === clues.length;

        if (isCorrect) {
            setGameState("solved");
            setShowConfetti(true);
            hapticSuccess();
            setMessage("Timeline stabilized. History is preserved thanks to your keen eye.");
            setMood("cheering");
        } else {
            hapticError();
            setMessage("The timeline is fragmented. Reorder the artifacts chronologically.");
            setTimeline([]);
            setMood("sad");
        }
    };

    return (
        <div className={`relative h-[650px] w-full rounded-[3rem] overflow-hidden border-4 border-white/10 ${NOIR_COLORS.bg} font-sans`}>
            {/* 4K Background Texture */}
            <div className="absolute inset-0 opacity-20 pointer-events-none">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_20%_20%,_#ffffff10_0%,_transparent_50%)]" />
                <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10" />
            </div>

            <AnimatePresence mode="wait">
                {gameState === "briefing" && (
                    <motion.div
                        key="briefing"
                        initial="initial"
                        animate="animate"
                        variants={JUICY_VARIANTS.impact}
                        className="absolute inset-0 z-30 flex flex-col items-center justify-center p-12 text-center space-y-8"
                    >
                        <div className="p-6 rounded-full bg-amber-400/20 border border-amber-400/30">
                            <Map className="w-16 h-16 text-amber-400" />
                        </div>
                        <div className="space-y-4">
                            <h2 className="text-5xl font-black text-white italic tracking-tighter uppercase">
                                Case #0{currentCaseIndex + 1}: <span className="text-amber-400">{currentCase.title}</span>
                            </h2>
                            <p className="text-slate-400 max-w-xl mx-auto text-lg leading-relaxed">
                                A temporal anomaly has scattered key historical data across the {currentCase.era}.
                                Recover the fragments and reconstruct the sequence of events.
                            </p>
                        </div>
                        <PhysicalButton onClick={startInvestigation} className="bg-amber-400 text-black h-16 px-12 text-xl">
                            BEGIN INVESTIGATION 🔎
                        </PhysicalButton>
                    </motion.div>
                )}

                {gameState === "investigation" && (
                    <motion.div
                        key="investigation"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="absolute inset-0 z-10"
                        ref={containerRef}
                        onMouseMove={handleSearch}
                        onTouchMove={handleSearch}
                    >
                        {/* Investigation HUD */}
                        <div className="absolute top-8 left-8 z-30 flex items-center gap-6 bg-black/60 backdrop-blur-xl border border-white/10 p-4 rounded-3xl">
                            <div className="flex items-center gap-2">
                                <Search className="w-5 h-5 text-amber-400" />
                                <span className="text-white font-black text-sm uppercase tracking-widest">Scanning {currentCase.era}...</span>
                            </div>
                            <div className="w-[1px] h-8 bg-white/10" />
                            <div className="flex items-center gap-2">
                                <Zap className="w-5 h-5 text-amber-400" />
                                <span className="text-white font-black text-sm uppercase tracking-widest">Clues: {foundCount}/{clues.length}</span>
                            </div>
                        </div>

                        {/* Search Magnifier */}
                        <motion.div
                            className="absolute pointer-events-none z-20"
                            animate={{ x: `${searchPos.x}%`, y: `${searchPos.y}%` }}
                            transition={JUICY_SPRINGS.stiff}
                            style={{ left: -100, top: -100 }}
                        >
                            <div className="w-[200px] h-[200px] rounded-full border-2 border-amber-400/50 flex items-center justify-center">
                                <div className="absolute inset-0 rounded-full bg-amber-400/5 blur-xl animate-pulse" />
                                <div className="w-[2px] h-[20px] bg-amber-400/80 absolute top-0" />
                                <div className="w-[2px] h-[20px] bg-amber-400/80 absolute bottom-0" />
                                <div className="h-[2px] w-[20px] bg-amber-400/80 absolute left-0" />
                                <div className="h-[2px] w-[20px] bg-amber-400/80 absolute right-0" />
                            </div>
                        </motion.div>

                        {/* Hidden Clues (Only visible when searching nearby) */}
                        {clues.map((clue) => {
                            const dist = Math.sqrt(Math.pow(searchPos.x - clue.x, 2) + Math.pow(searchPos.y - clue.y, 2));
                            const isNearby = dist < 15;
                            const isFound = clue.found;

                            return (
                                <motion.div
                                    key={clue.id}
                                    className="absolute"
                                    style={{ left: `${clue.x}%`, top: `${clue.y}%` }}
                                >
                                    <AnimatePresence>
                                        {(isNearby || isFound) && (
                                            <motion.div
                                                initial={{ scale: 0, opacity: 0 }}
                                                animate={{ scale: 1, opacity: isFound ? 1 : 0.6 }}
                                                className={`p-4 rounded-2xl ${isFound ? 'bg-amber-400 text-black' : 'bg-white/10 text-white border border-white/20'}`}
                                            >
                                                {isFound ? <CheckCircle2 className="w-8 h-8" /> : <Search className="w-8 h-8 opacity-50" />}
                                            </motion.div>
                                        )}
                                    </AnimatePresence>
                                </motion.div>
                            );
                        })}
                    </motion.div>
                )}

                {gameState === "deduction" && (
                    <motion.div
                        key="deduction"
                        {...JUICY_VARIANTS.slideUp}
                        className="absolute inset-0 z-20 p-12 flex flex-col items-center space-y-12"
                    >
                        <header className="text-center">
                            <h2 className="text-4xl font-black text-white italic tracking-tighter uppercase">Reconstruct Timeline</h2>
                            <p className="text-slate-400 mt-2">Drag artifacts into the sequence chronologically.</p>
                        </header>

                        <div className="flex flex-wrap justify-center gap-6">
                            {clues.map(clue => {
                                const inTimeline = timeline.find(c => c.id === clue.id);
                                return (
                                    <motion.div
                                        key={clue.id}
                                        whileHover={{ y: -5 }}
                                        onClick={() => addToTimeline(clue)}
                                        className={`p-6 rounded-3xl border-2 cursor-pointer transition-all ${inTimeline
                                            ? 'bg-amber-400/10 border-amber-400/30 opacity-30 grayscale'
                                            : 'bg-white/5 border-white/10 hover:border-amber-400/50'
                                            }`}
                                    >
                                        <div className="flex flex-col items-center space-y-3">
                                            {clue.category === 'document' && <BookOpen className="w-10 h-10 text-amber-400" />}
                                            {clue.category === 'tool' && <Clock className="w-10 h-10 text-amber-400" />}
                                            {clue.category === 'artifact' && <Shield className="w-10 h-10 text-amber-400" />}
                                            <span className="text-white font-bold text-sm text-center max-w-[100px]">{clue.name}</span>
                                        </div>
                                    </motion.div>
                                );
                            })}
                        </div>

                        {/* Drop Zone / Timeline */}
                        <div className="w-full max-w-4xl bg-white/5 border border-white/10 p-8 rounded-[3rem] min-h-[160px] flex items-center justify-center gap-6">
                            {timeline.length === 0 && (
                                <span className="text-slate-600 font-bold uppercase tracking-widest flex items-center gap-3">
                                    <Clock className="w-6 h-6" /> Assemble Event Sequence
                                </span>
                            )}
                            {timeline.map((item, idx) => (
                                <motion.div
                                    key={item.id}
                                    initial={{ scale: 0 }}
                                    animate={{ scale: 1 }}
                                    className="relative flex items-center gap-6"
                                >
                                    <div className="bg-amber-400 text-black p-4 rounded-2xl font-black italic shadow-[0_0_20px_rgba(251,191,36,0.3)]">
                                        {item.name}
                                    </div>
                                    {idx < clues.length - 1 && (
                                        <div className="w-8 h-[2px] bg-white/20" />
                                    )}
                                </motion.div>
                            ))}
                        </div>

                        <div className="flex gap-4">
                            <PhysicalButton
                                onClick={() => setTimeline([])}
                                className="bg-white/10 text-white h-14 px-8 border border-white/10"
                            >
                                <RotateCcw className="w-5 h-5 mr-2" /> RESET
                            </PhysicalButton>
                            <PhysicalButton
                                onClick={checkTimeline}
                                className="bg-amber-400 text-black h-14 px-12 text-lg disabled:opacity-50"
                                disabled={timeline.length < clues.length}
                            >
                                STABILIZE NARRATIVE
                            </PhysicalButton>
                        </div>
                    </motion.div>
                )}

                {gameState === "solved" && (
                    <motion.div
                        key="solved"
                        {...JUICY_VARIANTS.slideUp}
                        className="absolute inset-0 z-30 flex flex-col items-center justify-center p-12 bg-black/80 backdrop-blur-3xl"
                    >
                        <JuicyConfetti active={showConfetti} />
                        <div className="text-center space-y-6">
                            <motion.div
                                animate={{ scale: [1, 1.2, 1] }}
                                transition={{ repeat: Infinity, duration: 2 }}
                                className="inline-block p-6 rounded-full bg-emerald-500/20 border border-emerald-500/30 mb-4"
                            >
                                <CheckCircle2 className="w-20 h-20 text-emerald-400" />
                            </motion.div>
                            <h2 className="text-6xl font-black text-white italic tracking-tighter uppercase">Temporal Lock Engaged</h2>
                            <p className="text-slate-400 text-xl max-w-lg mx-auto">
                                The {currentCase.era} has been restored to its proper sequence. High-fidelity historical data sync successful.
                            </p>
                            <div className="pt-8">
                                <PhysicalButton
                                    onClick={() => {
                                        setGameState("briefing");
                                        setCurrentCaseIndex((currentCaseIndex + 1) % HISTORICAL_CASES.length);
                                        setTimeline([]);
                                        setFoundCount(0);
                                        setShowConfetti(false);
                                    }}
                                    className="bg-emerald-500 text-black h-16 px-12 text-xl"
                                >
                                    NEXT CHRONICLE 📖
                                </PhysicalButton>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Juice: Streak Overlay */}
            <div className="absolute top-8 right-8 z-30">
                <JuicyStreak count={foundCount} />
            </div>
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { ShieldCheck, Lock, Unlock, Zap, Terminal, Cpu, Database, Network, EyeOff, Key } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Cipher Types --- */
type Signal = {
    id: string;
    encrypted: string;
    decrypted: string;
    hint: string;
    complexity: number;
};

export default function CipherCity() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"IDLE" | "DECRYPTING" | "BREACHED" | "SECURED">("IDLE");
    const [currentSignal, setCurrentSignal] = useState<Signal | null>(null);
    const [userInput, setUserInput] = useState("");
    const [timeLeft, setTimeLeft] = useState(30);
    const [score, setScore] = useState(0);
    const [level, setLevel] = useState(1);

    const signals: Signal[] = useMemo(() => [
        { id: "s1", encrypted: "Koydo Is Fun", decrypted: "Koydo Is Fun", hint: "Direct Input Test", complexity: 1 },
        { id: "s2", encrypted: "Bqqmf", decrypted: "Apple", hint: "Shift forward by 1", complexity: 2 },
        { id: "s3", encrypted: "Ufdi", decrypted: "Tech", hint: "Shift forward by 1", complexity: 2 },
        { id: "s4", encrypted: "Dzfsh", decrypted: "Cyber", hint: "Shift forward by 1", complexity: 3 }
    ], []);

    const nextLevel = useCallback(() => {
        const signal = signals[Math.min(level - 1, signals.length - 1)];
        setCurrentSignal(signal);
        setUserInput("");
        setTimeLeft(30);
        setGameState("DECRYPTING");
        setMood("thinking");
        setMessage(`Signal intercepted! Complexity Level ${level}. Break the cipher before the firewall resets! 🕵️‍♂️`);
    }, [level, signals, setMessage, setMood]);

    const startBreach = () => {
        setScore(0);
        setLevel(1);
        nextLevel();
        hapticSuccess();
    };

    const handleInput = (char: string) => {
        if (gameState !== "DECRYPTING") return;
        setUserInput(prev => prev + char);
        hapticSelection();
    };

    const checkDecryption = useCallback(() => {
        if (!currentSignal) return;
        if (userInput.toLowerCase() === currentSignal.decrypted.toLowerCase()) {
            setScore(s => s + (timeLeft * 100));
            if (level < signals.length) {
                setLevel(l => l + 1);
                hapticSuccess();
                setMessage("Signal decrypted! Moving to the next node... ⚡");
            } else {
                setGameState("SECURED");
                hapticSuccess();
                setMessage("Mainframe Access Granted! All signals secured. 🏆");
            }
        } else {
            hapticError();
            setUserInput(""); // Reset on wrong try for challenge
        }
    }, [userInput, currentSignal, timeLeft, level, signals.length, setMessage]);

    // Timer Loop
    useEffect(() => {
        if (gameState !== "DECRYPTING" || timeLeft <= 0) return;
