                                        >
                                            {impactText}
                                        </motion.div>
                                    ) : (
                                        <motion.div
                                            key="narrative"
                                            initial={{ opacity: 0 }}
                                            animate={{ opacity: 1 }}
                                            className="space-y-4"
                                        >
                                            <h3 className="text-purple-400 font-black text-xs tracking-widest uppercase flex items-center gap-2">
