                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Win Screen */}
            <AnimatePresence>
                {isComplete && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        className="absolute inset-0 bg-slate-950/98 backdrop-blur-3xl flex items-center justify-center z-50 p-12 text-center"
                    >
                        <motion.div
                            initial={{ scale: 0.8, y: 30 }}
