            {/* CRT Distortion Overlay */}
            <div className="absolute inset-0 pointer-events-none z-50 opacity-20 bg-[radial-gradient(circle_at_center,transparent_0%,rgba(0,0,0,0.4)_100%)] mix-blend-overlay" />
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { Activity, ShieldCheck, Info, ChevronRight, Zap, Target, Microscope, Atom, Dna, Waves, Thermometer, Wind } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Microbiology Types --- */
type CellStructure = "NUCLEUS" | "MITOCHONDRIA" | "RIBOSOME" | "MEMBRANE";

type NanoStats = {
    integrity: number;
    energy: number;
    depth: number;
    resolution: number;
};

export default function NanoNavigator() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"IDLE" | "NAVIGATING" | "SAMPLING" | "DANGER">("IDLE");
    const [stats, setStats] = useState<NanoStats>({
        integrity: 100,
        energy: 100,
        depth: 0,
        resolution: 4
    });
    const [position, setPosition] = useState({ x: 50, y: 50 });
    const [samples, setSamples] = useState<CellStructure[]>([]);

    const updateMovement = useCallback((dx: number, dy: number) => {
        if (gameState !== "NAVIGATING") return;

        setPosition(prev => ({
            x: Math.min(90, Math.max(10, prev.x + dx)),
            y: Math.min(90, Math.max(10, prev.y + dy))
        }));

        setStats(prev => ({
            ...prev,
            energy: Math.max(0, prev.energy - 0.2),
            depth: prev.depth + 1
        }));

        if (stats.energy < 10) {
            setMessage("Energy reserves critical. Atomic propulsion failing. 🔋");
            setMood("thinking");
        }
    }, [gameState, stats.energy]);

    useEffect(() => {
        const handleKeys = (e: KeyboardEvent) => {
            if (e.key === "ArrowUp") updateMovement(0, -2);
            if (e.key === "ArrowDown") updateMovement(0, 2);
            if (e.key === "ArrowLeft") updateMovement(-2, 0);
            if (e.key === "ArrowRight") updateMovement(2, 0);
        };
        window.addEventListener("keydown", handleKeys);
        return () => window.removeEventListener("keydown", handleKeys);
    }, [updateMovement]);

    const collectSample = (type: CellStructure) => {
        if (samples.includes(type)) return;
        setSamples(prev => [...prev, type]);
        hapticSuccess();
        setMessage(`Biological sample acquired: ${type}. Atomic sequencing complete. 🧬`);
        setMood("happy");

        if (samples.length + 1 === 4) {
            setGameState("SAMPLING");
            setMessage("Metastructure mapping complete. You've successfully navigated the atomic realm. 🏆");
        }
    };

    const startMission = () => {
        setGameState("NAVIGATING");
        setMood("thinking");
        setMessage("Miniaturization complete. Atomic drive engaged. Explore the cellular landscape. 🔬");
        hapticSelection();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[700px] bg-indigo-950/20 rounded-[4rem] border border-indigo-500/20 overflow-hidden shadow-2xl flex flex-col font-sans text-white">
            {/* Molecular Background */}
            <div className="absolute inset-0 z-0">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(99,102,241,0.1)_0%,transparent_70%)]" />
                {/* Floating Atoms */}
                {Array.from({ length: 15 }).map((_, i) => (
                    <motion.div
                        key={i}
                        animate={{
                            x: [Math.random() * 1000, Math.random() * 1000],
                            y: [Math.random() * 700, Math.random() * 700],
                            opacity: [0.1, 0.3, 0.1]
                        }}
                        transition={{ duration: 10 + Math.random() * 20, repeat: Infinity }}
                        className="absolute w-2 h-2 rounded-full bg-indigo-400/20 blur-sm"
                    />
                ))}
            </div>

            {/* HUD */}
            <div className="relative z-20 p-8 flex justify-between items-center bg-zinc-900/60 backdrop-blur-2xl border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-2xl bg-indigo-500/10 border border-indigo-500/30 flex items-center justify-center">
                        <Microscope className="text-indigo-400 w-8 h-8" />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black italic tracking-tighter text-white uppercase leading-none">Nano Navigator</h2>
                        <span className="text-[10px] font-bold text-indigo-600 uppercase tracking-widest">Atomic Probe v4.2</span>
                    </div>
                </div>

                <div className="flex gap-4">
                    <HudMeter label="Structure Integrity" value={stats.integrity} color="bg-emerald-500" />
                    <HudMeter label="Power Core" value={stats.energy} color="bg-sky-500" />
                    <div className="bg-white/5 border border-white/5 px-6 py-2 rounded-2xl flex flex-col items-end">
                        <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">RESOLUTION</span>
                        <span className="text-lg font-black italic text-indigo-400 tabular-nums">{stats.resolution}K HDR</span>
                    </div>
                </div>
            </div>

            {/* Atomic Viewport */}
            <div className="relative z-10 flex-1 flex overflow-hidden">
                {/* Left: Sensor Array */}
                <div className="w-80 border-r border-white/5 p-8 flex flex-col gap-6 bg-zinc-900/40">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-2 flex items-center gap-2">
                        <Activity className="w-3 h-3 text-indigo-400" /> Spectrum Sensor
                    </h3>

                    <SensorCard label="Thermal Variance" value="+2.4°C" icon={Thermometer} />
                    <SensorCard label="Molecular Flow" value="0.5 nm/s" icon={Waves} />
                    <SensorCard label="Photon Density" value="High" icon={Zap} />

                    <div className="mt-auto pt-8 border-t border-white/5">
                        <h4 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-4">Sample Collection</h4>
                        <div className="grid grid-cols-2 gap-2">
                            {(["NUCLEUS", "MITOCHONDRIA", "RIBOSOME", "MEMBRANE"] as CellStructure[]).map(s => (
                                <div key={s} className={`p-2 rounded-xl border text-[8px] font-black text-center transition-all
                                    ${samples.includes(s) ? 'bg-indigo-500/20 border-indigo-500 text-indigo-400' : 'bg-black/20 border-white/5 text-zinc-600'}`}>
                                    {s}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Right: The Microcosm */}
                <div className="flex-1 relative p-12 bg-black/20 overflow-hidden cursor-none">
                    {/* Organic Landscape */}
                    <svg className="absolute inset-0 w-full h-full opacity-30 blur-2xl pointer-events-none">
                        <circle cx="20%" cy="30%" r="100" fill="rgba(99,102,241,0.2)" />
                        <circle cx="80%" cy="70%" r="150" fill="rgba(168,85,247,0.2)" />
                        <rect x="40%" y="40%" width="200" height="200" rx="100" fill="rgba(16,185,129,0.1)" />
                    </svg>

                    {/* Interactive Structures */}
                    <StructureNode name="NUCLEUS" x={30} y={30} icon={Atom} color="text-indigo-400" onCollect={() => collectSample("NUCLEUS")} />
                    <StructureNode name="POWER" x={70} y={20} icon={Zap} color="text-amber-400" onCollect={() => collectSample("MITOCHONDRIA")} />
                    <StructureNode name="CODING" x={20} y={70} icon={Dna} color="text-rose-400" onCollect={() => collectSample("RIBOSOME")} />
                    <StructureNode name="BARRIER" x={80} y={80} icon={ShieldCheck} color="text-emerald-400" onCollect={() => collectSample("MEMBRANE")} />

                    {/* The Nano Probe */}
                    <motion.div
                        animate={{
                            left: `${position.x}%`,
                            top: `${position.y}%`,
                            rotate: 360
                        }}
                        transition={{ duration: 0.1, rotate: { duration: 10, repeat: Infinity, ease: "linear" } }}
                        className="absolute w-12 h-12 -ml-6 -mt-6 z-50 pointer-events-none"
                    >
                        <div className="relative w-full h-full flex items-center justify-center">
                            <div className="absolute inset-0 rounded-full border border-indigo-500/40 animate-ping opacity-20" />
                            <div className="w-8 h-8 rounded-full bg-indigo-500 border-4 border-white shadow-[0_0_20px_rgba(99,102,241,0.5)] flex items-center justify-center">
                                <Target className="w-4 h-4 text-white" />
                            </div>
                        </div>
                    </motion.div>
                </div>
            </div>

            {/* Victory Overlay */}
            <AnimatePresence>
                {gameState === "SAMPLING" && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        className="absolute inset-0 z-40 bg-zinc-950/80 backdrop-blur-3xl flex flex-col items-center justify-center p-12 text-center"
                    >
                        <div className="w-24 h-24 bg-indigo-500/20 rounded-[2.5rem] flex items-center justify-center border border-indigo-500/30 mb-8 overflow-hidden group shadow-[0_0_40px_rgba(99,102,241,0.2)]">
                            <Microscope className="w-12 h-12 text-indigo-400 group-hover:scale-110 transition-transform" />
                        </div>
                        <h3 className="text-5xl font-black italic tracking-tighter text-white mb-4 uppercase leading-none">Atomic Mastery</h3>
                        <p className="text-zinc-500 text-sm max-w-sm mb-12 italic leading-relaxed">
                            Mission success. All cellular structures mapped and biological data synthesized at the atomic scale.
                        </p>
                        <PhysicalButton
                            onClick={() => window.location.reload()}
                            className="bg-indigo-600 h-24 px-20 rounded-[3rem] text-2xl shadow-lg border border-indigo-400/30"
                        >
                            RETURN TO HUB 🚀
                        </PhysicalButton>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Start Overlay */}
            {gameState === "IDLE" && (
                <motion.div
                    {...JUICY_VARIANTS.slideUp}
                    className="absolute inset-0 z-40 bg-zinc-950/90 backdrop-blur-3xl flex flex-col items-center justify-center p-12 text-center"
                >
                    <div className="w-24 h-24 bg-indigo-500/20 rounded-[2.5rem] flex items-center justify-center border border-indigo-500/30 mb-8 overflow-hidden group">
                        <Atom className="w-12 h-12 text-indigo-400 group-hover:rotate-180 transition-transform duration-1000" />
                    </div>
                    <h3 className="text-5xl font-black italic tracking-tighter text-white mb-4 uppercase leading-none">Nano Navigation</h3>
                    <p className="text-zinc-500 text-sm max-w-sm mb-12 italic leading-relaxed">
                        Journey into the microscopic world. Navigate cellular landscapes, collect biological samples, and master the scale of atoms in 4K.
                    </p>
                    <PhysicalButton
                        onClick={startMission}
                        className="bg-indigo-600 h-24 px-20 rounded-[3rem] text-2xl shadow-lg border border-indigo-400/30"
                    >
                        ENGAGE PROBE 🔬
                    </PhysicalButton>
                </motion.div>
            )}
        </div>
    );
}

function HudMeter({ label, value, color }: { label: string, value: number, color: string }) {
    return (
        <div className="flex flex-col items-end gap-1">
            <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">{label}</span>
            <div className="w-32 h-1.5 bg-white/5 rounded-full overflow-hidden border border-white/5">
                <motion.div
                    animate={{ width: `${value}%` }}
                    className={`h-full ${color}`}
                />
            </div>
        </div>
    );
}

function SensorCard({ label, value, icon: Icon }: any) {
    return (
        <div className="bg-white/5 border border-white/5 p-4 rounded-2xl flex items-center justify-between">
            <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-lg bg-zinc-800 flex items-center justify-center">
                    <Icon className="w-4 h-4 text-indigo-400" />
                </div>
                <span className="text-[10px] font-black uppercase text-zinc-400">{label}</span>
            </div>
            <span className="text-xs font-black text-white tabular-nums">{value}</span>
        </div>
    );
}

function StructureNode({ name, x, y, icon: Icon, color, onCollect }: any) {
    return (
        <motion.button
            onClick={onCollect}
            whileHover={{ scale: 1.1 }}
            className="absolute p-4 rounded-3xl bg-zinc-900/40 border-2 border-white/5 backdrop-blur-xl flex flex-col items-center gap-2 group transition-all hover:bg-zinc-800/60"
            style={{ left: `${x}%`, top: `${y}%` }}
        >
            <div className={`p-4 rounded-2xl bg-zinc-800 border border-white/5 ${color} shadow-lg`}>
                <Icon className="w-8 h-8 group-hover:scale-110 transition-transform" />
            </div>
            <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">{name}</span>
        </motion.button>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useMascot } from "@/components/experience/MascotHost";
import { JUICY_VARIANTS, EXPERIENCE_COLORS } from "@/lib/experience/interaction-primitives";
import PhysicalButton from "@/components/experience/PhysicalButton";
import JuicyStreak from "@/components/experience/JuicyStreak";
import JuicyConfetti from "@/components/experience/JuicyConfetti";
import { hapticSuccess, hapticError, hapticCelebration } from "@/lib/platform/haptics";
import { Activity, Brain, Zap } from "lucide-react";

/* --- Types --- */
type Node = {
    id: number;
    x: number;
    y: number;
    active: boolean;
};

export default function NeuralNavigator() {
    const { setMood, setMessage } = useMascot();
    const [nodes, setNodes] = useState<Node[]>([]);
    const [sequence, setSequence] = useState<number[]>([]);
    const [userSequence, setUserSequence] = useState<number[]>([]);
    const [gameState, setGameState] = useState<"idle" | "showing" | "playing" | "success" | "fail">("idle");
    const [level, setLevel] = useState(1);
    const [streak, setStreak] = useState(0);

    // Initial message from Terra
    useEffect(() => {
        setMessage("Welcome to the Neural Lab! Let's map some synapses. 🧠");
        setMood("happy");
        generateNodes();
    }, []);

    const generateNodes = useCallback(() => {
        const newNodes: Node[] = [];
        const nodeCount = 5 + Math.floor(level / 2);
        for (let i = 0; i < nodeCount; i++) {
            newNodes.push({
                id: i,
                x: 10 + Math.random() * 80,
                y: 10 + Math.random() * 80,
                active: false
            });
        }
        setNodes(newNodes);
    }, [level]);

    const startRound = () => {
        const newSequence: number[] = [];
        const length = 3 + Math.floor(level / 3);
        const nodeCount = nodes.length;

        for (let i = 0; i < length; i++) {
            newSequence.push(Math.floor(Math.random() * nodeCount));
        }

        setSequence(newSequence);
        setUserSequence([]);
        setGameState("showing");
        playSequence(newSequence);
    };

    const playSequence = async (seq: number[]) => {
        setMessage("Watch closely... 👁️");
        setMood("thinking");

        for (let i = 0; i < seq.length; i++) {
            const nodeId = seq[i];
            setNodes(prev => prev.map(n => n.id === nodeId ? { ...n, active: true } : n));
            await new Promise(r => setTimeout(r, 600));
            setNodes(prev => prev.map(n => n.id === nodeId ? { ...n, active: false } : n));
            await new Promise(r => setTimeout(r, 200));
        }

        setGameState("playing");
        setMessage("Your turn! Re-map the path. ⚡");
    };

    const handleNodeClick = (nodeId: number) => {
        if (gameState !== "playing") return;

        const expectedId = sequence[userSequence.length];

        if (nodeId === expectedId) {
            void hapticSuccess();
            const newUserSeq = [...userSequence, nodeId];
            setUserSequence(newUserSeq);

            if (newUserSeq.length === sequence.length) {
                handleSuccess();
            }
        } else {
            handleFail();
        }
    };

    const handleSuccess = () => {
        setGameState("success");
        setStreak(prev => prev + 1);
        setLevel(prev => prev + 1);
        setMood("happy");
        setMessage("Perfect connection! The brain is firing! 🔥");
        void hapticCelebration();

        setTimeout(() => {
            setGameState("idle");
            generateNodes();
        }, 2000);
    };

    const handleFail = () => {
        setGameState("fail");
        setStreak(0);
        setMood("sad");
        setMessage("Synapse broken... Let's try that again. 🧬");
        void hapticError();

        setTimeout(() => {
            setGameState("idle");
            setUserSequence([]);
        }, 2000);
    };

    return (
        <div className="relative min-h-[600px] w-full flex flex-col items-center justify-center p-8 bg-slate-900 overflow-hidden rounded-[3rem] border border-white/10 shadow-2xl">
            {/* Background Bio-Texture */}
            <div className="absolute inset-0 opacity-20 pointer-events-none">
                <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-emerald-500/20 via-transparent to-transparent" />
            </div>

            <JuicyConfetti active={gameState === "success"} durationMs={1500} />

            {/* Header Stats */}
            <div className="absolute top-8 left-8 right-8 flex justify-between items-center z-10">
                <div className="flex flex-col">
                    <span className="text-[10px] font-black uppercase text-emerald-500 tracking-widest">Neural Complexity</span>
                    <span className="text-3xl font-black italic text-white leading-none">Level {level}</span>
                </div>
                <JuicyStreak count={streak} />
            </div>

            {/* The Brain Map Area */}
            <div className="relative w-full h-[400px] mt-12 bg-black/40 rounded-[2.5rem] border border-white/5 backdrop-blur-sm overflow-hidden">
                <AnimatePresence>
                    {nodes.map((node) => (
                        <motion.button
                            key={node.id}
                            style={{ left: `${node.x}%`, top: `${node.y}%` }}
                            variants={JUICY_VARIANTS.pressable}
                            initial="initial"
                            whileHover="hover"
                            whileTap="tap"
                            onClick={() => handleNodeClick(node.id)}
                            className="absolute -translate-x-1/2 -translate-y-1/2"
                        >
                            <div className={`relative w-12 h-12 rounded-full flex items-center justify-center transition-all duration-300 ${node.active || (gameState === "playing" && userSequence.includes(node.id))
                                    ? "bg-emerald-400 shadow-[0_0_25px_rgba(52,211,153,0.8)] scale-110"
                                    : "bg-white/10 hover:bg-white/20 border border-white/10"
                                }`}>
                                <Zap className={`w-5 h-5 ${node.active ? "text-white" : "text-emerald-500/50"}`} />

                                {/* Pulse Effect */}
                                {node.active && (
                                    <motion.div
                                        initial={{ scale: 1, opacity: 1 }}
                                        animate={{ scale: 2, opacity: 0 }}
                                        className="absolute inset-0 rounded-full bg-emerald-400"
                                    />
                                )}
                            </div>
                        </motion.button>
                    ))}
                </AnimatePresence>

                {/* Connection lines (Simulated simplified) */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none opacity-20">
                    {/* In a real production app, we'd draw lines between nodes here */}
                </svg>
            </div>

            {/* Game Controls */}
            <div className="mt-8 z-10">
                <AnimatePresence mode="wait">
                    {gameState === "idle" && (
                        <motion.div
                            key="start-btn"
                            initial={{ scale: 0.8, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.8, opacity: 0 }}
                        >
                            <PhysicalButton
                                onClick={startRound}
                                className="bg-emerald-600 px-12 h-16 rounded-2xl text-xl"
                            >
                                FIRE NEURONS ⚡
                            </PhysicalButton>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Terra's Hint Tooltip */}
            <div className="absolute bottom-8 left-8 flex items-center gap-4 bg-emerald-950/50 border border-emerald-500/20 px-6 py-3 rounded-2xl backdrop-blur-md">
                <Brain className="text-emerald-400 w-5 h-5" />
                <span className="text-xs font-bold text-emerald-200">Terra is observing your synaptic patterns.</span>
            </div>
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useRef } from "react";
import { Globe, Satellite, Zap, Target, RefreshCcw, Gauge, Layers, ShieldAlert } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Orbital Types --- */
type Body = {
    x: number;
    y: number;
    vx: number;
    vy: number;
    mass: number;
    radius: number;
    type: "earth" | "satellite" | "debris";
};

export default function OrbitOperator() {
    const { setMessage, setMood } = useMascot();
    const [satellite, setSatellite] = useState<Body | null>(null);
    const [gameState, setGameState] = useState<"IDLE" | "LAUNCHING" | "ORBITING" | "CRASHED" | "LOST">("IDLE");
    const [launchVector, setLaunchVector] = useState<{ x: number; y: number } | null>(null);
    const [score, setScore] = useState(0);
    const [attempts, setAttempts] = useState(3);
    const containerRef = useRef<HTMLDivElement>(null);

    const earth: Body = { x: 50, y: 50, vx: 0, vy: 0, mass: 5000, radius: 10, type: "earth" };

    // Physics constants
    const G = 0.5;
    const DT = 0.1;

    const resetGame = useCallback(() => {
        setSatellite(null);
        setLaunchVector(null);
        setGameState("IDLE");
        setScore(0);
        setAttempts(3);
        setMood("thinking");
        setMessage("Mission Control: Launch the satellite into the stable green orbit. Watch your trajectory! 🌍");
    }, [setMessage, setMood]);

    const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
        if (gameState !== "IDLE" || attempts <= 0) return;
        const rect = containerRef.current?.getBoundingClientRect();
        if (!rect) return;

        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

        const x = ((clientX - rect.left) / rect.width) * 100;
        const y = ((clientY - rect.top) / rect.height) * 100;
        setLaunchVector({ x, y });
        hapticSelection();
    };

    const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
        if (!launchVector || gameState !== "IDLE") return;
        const rect = containerRef.current?.getBoundingClientRect();
        if (!rect) return;

        const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
        const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

        const x = ((clientX - rect.left) / rect.width) * 100;
        const y = ((clientY - rect.top) / rect.height) * 100;
        setLaunchVector({ x: launchVector.x, y: launchVector.y }); // Just to trigger re-render if needed, but we track the 'current' position
    };

    const launch = (e: React.MouseEvent | React.TouchEvent) => {
        if (!launchVector || gameState !== "IDLE") return;

        const rect = containerRef.current?.getBoundingClientRect();
        if (!rect) return;

        const clientX = 'changedTouches' in e ? e.changedTouches[0].clientX : e.clientX;
        const clientY = 'changedTouches' in e ? e.changedTouches[0].clientY : e.clientY;

        const x = ((clientX - rect.left) / rect.width) * 100;
        const y = ((clientY - rect.top) / rect.height) * 100;

        const dx = launchVector.x - x;
        const dy = launchVector.y - y;

        setSatellite({
            x: launchVector.x,
            y: launchVector.y,
            vx: dx * 0.1,
            vy: dy * 0.1,
            mass: 1,
            radius: 2,
            type: "satellite"
        });

        setGameState("LAUNCHING");
        setLaunchVector(null);
        setAttempts(a => a - 1);
        hapticSuccess();
    };

    // Orbital Simulation Loop
    useEffect(() => {
        if (!satellite || (gameState !== "LAUNCHING" && gameState !== "ORBITING")) return;

        const interval = setInterval(() => {
            setSatellite(prev => {
                if (!prev) return null;

                const dx = earth.x - prev.x;
                const dy = earth.y - prev.y;
                const distSq = dx * dx + dy * dy;
                const dist = Math.sqrt(distSq);

                // Collision Check
                if (dist < earth.radius + prev.radius) {
                    setGameState("CRASHED");
                    hapticError();
                    setMessage("Atmospheric reentry failed. The satellite burned up! Try a higher trajectory. 🔥");
                    return prev;
                }

                // Out of Bounds
                if (prev.x < -50 || prev.x > 150 || prev.y < -50 || prev.y > 150) {
                    setGameState("LOST");
                    setMessage("Escape velocity reached. The satellite is lost in deep space. 🛰️");
                    return prev;
                }

                // Gravity
                const force = (G * earth.mass * prev.mass) / distSq;
                const ax = (dx / dist) * force;
                const ay = (dy / dist) * force;

                const nvx = prev.vx + ax * DT;
                const nvy = prev.vy + ay * DT;
                const nx = prev.x + nvx * DT;
                const ny = prev.y + nvy * DT;

                // Orbit Stability Check (Simplified)
                const speed = Math.sqrt(nvx * nvx + nvy * nvy);
                const targetDist = 35; // Target orbit radius
                if (Math.abs(dist - targetDist) < 5 && Math.abs(speed - 3.8) < 0.5) {
                    if (gameState !== "ORBITING") {
                        setGameState("ORBITING");
                        setScore(s => s + 5000);
                        hapticSuccess();
                        setMessage("Stable orbit achieved! Excellent calculation, Operator. 🚀");
                    }
                }

                return { ...prev, x: nx, y: ny, vx: nvx, vy: nvy };
            });
        }, 16);

        return () => clearInterval(interval);
    }, [satellite, gameState, setMessage]);

    return (
        <div
            ref={containerRef}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={launch}
            onTouchStart={handleMouseDown}
            onTouchMove={handleMouseMove}
            onTouchEnd={launch}
            className="relative w-full max-w-5xl mx-auto h-[700px] bg-slate-950 rounded-[4rem] border border-white/5 overflow-hidden shadow-2xl flex flex-col font-mono cursor-crosshair select-none"
        >
            {/* Deep Space Background */}
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(56,189,248,0.1)_0%,transparent_70%)]" />
                {/* Star Field Simulation */}
                <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]" />
            </div>

            {/* HUD: Top Metrics */}
            <div className="relative z-20 p-10 flex justify-between items-start pointer-events-none">
                <div className="space-y-4">
                    <div className="bg-white/5 border border-white/10 p-5 rounded-[2rem] backdrop-blur-2xl">
                        <div className="flex items-center gap-3 mb-1">
                            <Satellite className="text-sky-400 w-5 h-5" />
                            <h2 className="text-xl font-black italic tracking-tighter text-white uppercase">Orbit Operator</h2>
                        </div>
                        <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.3em]">Trajectory Analysis System v4.0</p>
                    </div>

                    <div className="flex gap-3">
                        {Array.from({ length: 3 }).map((_, i) => (
                            <div
                                key={i}
                                className={`w-10 h-10 rounded-xl border flex items-center justify-center transition-colors
                                    ${i < attempts ? 'bg-sky-500/20 border-sky-500/30 text-sky-400' : 'bg-white/5 border-white/10 text-white/10'}`}
                            >
                                <Satellite className="w-5 h-5" />
                            </div>
                        ))}
                    </div>
                </div>

                <div className="bg-white/5 border border-white/10 p-5 rounded-[2rem] backdrop-blur-2xl min-w-[150px]">
                    <div className="flex justify-between items-center mb-1">
                        <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Orbital Sync</span>
                        <Gauge className="text-sky-400 w-3 h-3" />
                    </div>
                    <p className="text-3xl font-black italic tracking-tighter tabular-nums text-white">{score.toLocaleString()}</p>
                </div>
            </div>

            {/* Simulation Space */}
            <div className="absolute inset-0 z-10 flex items-center justify-center pointer-events-none">
                {/* Target Orbit Ring */}
                <div className="absolute w-[70%] aspect-square rounded-full border-2 border-emerald-500/20 border-dashed animate-spin-slow" />

                {/* Earth Body */}
                <motion.div
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    className="relative w-32 h-32 rounded-full bg-sky-500 shadow-[0_0_50px_rgba(14,165,233,0.3)] z-10 flex items-center justify-center overflow-hidden"
                >
                    <div className="absolute inset-0 bg-[linear-gradient(135deg,rgba(255,255,255,0.2),transparent)]" />
                    <Globe className="text-white/80 w-16 h-16 animate-pulse" />
                </motion.div>

                {/* The Satellite */}
                {satellite && (
                    <motion.div
                        className="absolute w-4 h-4 rounded-full bg-white shadow-[0_0_15px_#fff] z-20 flex items-center justify-center"
                        style={{
                            left: `${satellite.x}%`,
                            top: `${satellite.y}%`,
                            x: "-50%",
                            y: "-50%"
                        }}
                    >
                        <Satellite className="w-2.5 h-2.5 text-sky-950" />
                    </motion.div>
                )}

                {/* Launch Vector Preview */}
                {launchVector && (
                    <div className="absolute z-20 pointer-events-none">
                        <div className="absolute w-2 h-2 rounded-full bg-sky-400" style={{ left: `${launchVector.x}%`, top: `${launchVector.y}%` }} />
                    </div>
                )}
            </div>

            {/* Game Over / Reset UI */}
            {(gameState === "CRASHED" || gameState === "LOST" || attempts === 0 && !satellite) && (
                <motion.div
                    {...JUICY_VARIANTS.slideUp}
                    className="absolute inset-0 z-40 bg-slate-950/90 backdrop-blur-3xl flex flex-col items-center justify-center p-12 text-center"
                >
                    <div className="bg-rose-500/20 p-8 rounded-[3rem] border border-rose-500/30 mb-8">
                        <ShieldAlert className="w-16 h-16 text-rose-400" />
                    </div>
                    <h3 className="text-5xl font-black italic tracking-tighter text-white mb-4 uppercase">Mission Terminated</h3>
                    <p className="text-zinc-400 text-sm max-w-sm mb-12">
                        Calculations failed to achieve orbital stability. Recalibrate and attempt another insertion.
                    </p>
                    <PhysicalButton onClick={resetGame} className="bg-sky-500 h-24 px-20 rounded-[3rem] text-2xl">
                        REBOOT SYSTEM 🔄
                    </PhysicalButton>
                </motion.div>
            )}

            {/* Bottom Bar: Instructions */}
            <div className="relative z-20 mt-auto p-10 flex justify-center">
                <div className="bg-white/5 border border-white/10 px-8 py-3 rounded-2xl backdrop-blur-xl">
                    <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Launch Protocol: Drag back to aim, release to fire satellite</p>
                </div>
            </div>

            {/* Scanline Detail */}
            <div className="absolute inset-0 pointer-events-none z-50 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.03)_50%)] bg-[length:100%_4px]" />
        </div>
    );
}

"use client";

import React, { useState, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
    Shield,
    Lock,
    Unlock,
    Terminal,
    Network,
    Cpu,
    CheckCircle2,
    AlertTriangle,
    Eye,
    Zap
} from "lucide-react";
import { hapticSuccess, hapticSelection } from "@/lib/platform/haptics";
import MascotFriend from "../experience/KoydoMascotFriends";

/**
 * PIXEL'S PATH - Phase 9 (Explorer Batch)
 * A 4K digital frontier quest focusing on network protocols and safety.
 * Theme: Sequential "Explorer" quests (Dora-style) to secure a digital landscape.
 */

interface ProtocolNode {
    id: string;
    step: string;
    description: string;
    challenge: string;
    answer: string;
    x: number;
    y: number;
}

const PROTOCOL_STEPS: ProtocolNode[] = [
    {
        id: "node_1",
        step: "Gateway Security",
        description: "The digital gates require a firewall. Identify the correct port for secure traffic.",
        challenge: "Secure Web Port? (443 or 80)",
        answer: "443",
        x: 20,
        y: 50
    },
    {
        id: "node_2",
        step: "Packet Inspection",
        description: "A suspicious packet is trying to enter. Verify the encryption key length.",
        challenge: "2^8 bits? (256 or 128)",
        answer: "256",
        x: 50,
        y: 20
    },
    {
        id: "node_3",
        step: "Core Protection",
        description: "The central mainframe needs a final lock. Close the loop.",
        challenge: "Enable MFA? (YES or NO)",
        answer: "YES",
        x: 80,
        y: 60
    }
];

export default function PixelsPath() {
    const [stepIndex, setStepIndex] = useState(0);
    const [securedNodes, setSecuredNodes] = useState<string[]>([]);
    const [userInput, setUserInput] = useState("");
    const [isComplete, setIsComplete] = useState(false);
    const [error, setError] = useState(false);

    const currentStep = PROTOCOL_STEPS[stepIndex];

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        const input = userInput.trim().toUpperCase();

        if (input === currentStep.answer) {
            handleSuccess();
        } else {
            setError(true);
            setTimeout(() => setError(false), 500);
            hapticSelection();
        }
    };

    const handleSuccess = useCallback(() => {
        hapticSuccess();
        setSecuredNodes(prev => [...prev, currentStep.id]);
        setUserInput("");

        if (stepIndex < PROTOCOL_STEPS.length - 1) {
            setStepIndex(prev => prev + 1);
        } else {
            setIsComplete(true);
        }
    }, [stepIndex, currentStep.id]);

    return (
        <div className="relative w-full aspect-video rounded-3xl overflow-hidden bg-slate-950 border border-blue-500/20 shadow-2xl font-sans group">
            {/* 4K Cyber-Grid Background */}
            <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1550751827-4bd374c3f58b?auto=format&fit=crop&q=80&w=2000')] bg-cover bg-center brightness-[0.2] opacity-50" />
            <div className="absolute inset-0 bg-gradient-to-tr from-blue-900/20 via-transparent to-purple-900/20" />

            {/* Network Nodes */}
            <svg className="absolute inset-0 w-full h-full pointer-events-none">
                <path
                    d={`M ${PROTOCOL_STEPS[0].x}% ${PROTOCOL_STEPS[0].y}% L ${PROTOCOL_STEPS[1].x}% ${PROTOCOL_STEPS[1].y}% L ${PROTOCOL_STEPS[2].x}% ${PROTOCOL_STEPS[2].y}%`}
                    fill="none"
                    stroke="rgba(59, 130, 246, 0.2)"
                    strokeWidth="2"
                    strokeDasharray="8 8"
                />
            </svg>

            <div className="absolute inset-0 pointer-events-none">
                {PROTOCOL_STEPS.map((node, idx) => (
                    <motion.div
                        key={node.id}
                        initial={{ scale: 0 }}
                        animate={{
                            scale: 1,
                            opacity: idx <= stepIndex ? 1 : 0.3
                        }}
                        className="absolute"
                        style={{ left: `${node.x}%`, top: `${node.y}%`, transform: 'translate(-50%, -50%)' }}
                    >
                        <div className={`p-4 rounded-xl border-2 backdrop-blur-3xl transition-all duration-500 ${securedNodes.includes(node.id) ? "bg-blue-500/20 border-blue-400" : idx === stepIndex ? "bg-white/5 border-blue-400/50 animate-pulse" : "bg-white/5 border-white/10"
                            }`}>
                            {securedNodes.includes(node.id) ? (
                                <Lock className="w-6 h-6 text-blue-400" />
                            ) : (
                                <Unlock className="w-6 h-6 text-white/30" />
                            )}
                        </div>
                    </motion.div>
                ))}
            </div>

            {/* HUD: Digital Firewall Status (Top Right) */}
            <div className="absolute top-6 right-6 flex items-center gap-4 bg-black/40 backdrop-blur-2xl border border-white/10 rounded-2xl p-4">
                <div className="flex flex-col items-end">
                    <span className="text-blue-400 text-[10px] font-black uppercase tracking-widest leading-none mb-1">Firewall Integrity</span>
                    <div className="text-xl font-mono font-bold text-white tracking-tighter">
                        {((securedNodes.length / PROTOCOL_STEPS.length) * 100).toFixed(0)}%
                    </div>
                </div>
                <Shield className={`w-8 h-8 ${securedNodes.length === PROTOCOL_STEPS.length ? "text-blue-400" : "text-white/20"}`} />
            </div>

            {/* HUD: Pixel Interaction & Challenge (Bottom) */}
            <div className="absolute bottom-6 left-6 right-6">
                <AnimatePresence mode="wait">
                    {!isComplete && (
                        <motion.div
                            key={stepIndex}
                            initial={{ y: 20, opacity: 0 }}
                            animate={{ y: 0, opacity: 1 }}
                            exit={{ y: -20, opacity: 0 }}
                            className="bg-slate-900/90 backdrop-blur-3xl border border-blue-500/30 rounded-3xl p-8 flex gap-8 items-center"
                        >
                            <div className="w-24 h-24 relative flex-shrink-0">
                                <MascotFriend id="pixel" size="lg" mood={error ? "thinking" : "happy"} />
                            </div>

                            <div className="flex-grow">
                                <h3 className="text-blue-400 font-black text-xs tracking-[0.2em] uppercase mb-2 flex items-center gap-2">
                                    <Terminal className="w-4 h-4" />
                                    Security Protocol: {currentStep.step}
                                </h3>
                                <p className="text-white text-xl font-medium leading-tight mb-2">
                                    {currentStep.description}
                                </p>
                                <div className="text-blue-400/80 font-mono text-sm flex items-center gap-2">
                                    <Eye className="w-4 h-4" />
                                    Challenge: {currentStep.challenge}
                                </div>
                            </div>

                            <form onSubmit={handleSubmit} className="flex gap-4">
                                <input
                                    autoFocus
                                    type="text"
                                    value={userInput}
                                    onChange={(e) => setUserInput(e.target.value)}
                                    placeholder="ENTRY"
                                    className={`w-32 px-4 py-4 bg-black/50 border-2 rounded-2xl text-center text-blue-400 font-mono text-xl font-bold transition-all outline-none ${error ? "border-red-500" : "border-blue-500/30 focus:border-blue-400"
                                        }`}
                                />
                                <button
                                    type="submit"
                                    className="px-8 py-4 bg-blue-500 text-white rounded-2xl font-black uppercase tracking-widest shadow-xl shadow-blue-500/30 hover:scale-105 active:scale-95 transition-all"
                                >
                                    Confirm
                                </button>
                            </form>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Win Screen */}
            <AnimatePresence>
                {isComplete && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        className="absolute inset-0 bg-slate-950/98 backdrop-blur-3xl flex items-center justify-center z-50 p-12 overflow-hidden text-center"
                    >
                        <motion.div
                            initial={{ scale: 0.8, y: 30 }}
                            animate={{ scale: 1, y: 0 }}
                            className="max-w-md w-full relative z-10"
                        >
                            <div className="w-40 h-40 mx-auto mb-8">
                                <MascotFriend id="pixel" size="xl" mood="happy" />
                            </div>

                            <div className="inline-flex p-3 bg-blue-500/10 border border-blue-500/20 rounded-2xl mb-6">
                                <Zap className="w-8 h-8 text-blue-400" />
                            </div>

                            <h2 className="text-6xl font-black text-white italic tracking-tighter uppercase mb-4 leading-none">
                                Firewall <br /> Engaged!
                            </h2>
                            <p className="text-white/60 mb-10 text-lg">
                                The digital landscape is secured. Your understanding of protocols has saved the network.
                            </p>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl">
                                    <div className="text-2xl font-bold text-white mb-1">SECURE</div>
                                    <div className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">Status</div>
                                </div>
                                <div className="bg-blue-500/10 border border-blue-500/20 p-4 rounded-2xl">
                                    <div className="text-2xl font-bold text-white mb-1">AES-256</div>
                                    <div className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">Encryption</div>
                                </div>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Global Overlays */}
            <div className="absolute inset-x-0 top-0 h-px bg-gradient-to-r from-transparent via-blue-500/50 to-transparent" />
            <div className="absolute inset-x-0 bottom-0 h-px bg-gradient-to-r from-transparent via-blue-500/50 to-transparent" />
        </div>
    );
}

"use client";

import { motion, AnimatePresence, useDragControls } from "framer-motion";
import { useState, useEffect, useRef, useCallback } from "react";
import { Atom, Zap, Maximize, Target, RefreshCcw, ShieldAlert, Cpu, Layers } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Types --- */
type QuantumParticle = {
    id: string;
    type: "electron" | "photon" | "quark";
    x: number;
    y: number;
    charge: number;
    mass: number;
};

type GravityWell = {
    id: string;
    x: number;
    y: number;
    strength: number;
    targetCharge: number;
};

export default function QuantumQuest() {
    const { setMessage, setMood } = useMascot();
    const [particles, setParticles] = useState<QuantumParticle[]>([]);
    const [wells, setWells] = useState<GravityWell[]>([]);
    const [gameState, setGameState] = useState<"IDLE" | "PLAYING" | "STABILIZED" | "CRITICAL">("IDLE");
    const [energyLevel, setEnergyLevel] = useState(100);
    const [score, setScore] = useState(0);

    const initializeLevel = useCallback(() => {
        const newWells: GravityWell[] = [
            { id: "well-1", x: 30, y: 50, strength: 0.5, targetCharge: 10 },
            { id: "well-2", x: 70, y: 50, strength: 0.5, targetCharge: -10 }
        ];
        setWells(newWells);
        setParticles([]);
        setEnergyLevel(100);
        setGameState("PLAYING");
        setScore(0);
        setMood("thinking");
        setMessage("Quantum stability critical. Deploy particles to balance the gravity wells! ⚛️");
    }, [setMessage, setMood]);

    const deployParticle = (type: QuantumParticle["type"], x: number, y: number) => {
        if (energyLevel <= 0 || gameState !== "PLAYING") return;

        const charges = { electron: -1, photon: 0, quark: 1 };
        const masses = { electron: 1, photon: 0.1, quark: 2 };

        const newParticle: QuantumParticle = {
            id: Math.random().toString(36).substr(2, 9),
            type,
            x: 50, // Origin
            y: 80,
            charge: charges[type],
            mass: masses[type]
        };

        setParticles(prev => [...prev, newParticle]);
        setEnergyLevel(e => Math.max(0, e - 10));
        hapticSelection();
    };

    // Physics Simulation Loop
    useEffect(() => {
        if (gameState !== "PLAYING") return;

        const interval = setInterval(() => {
            setParticles(prev => {
                let updated = prev.map(p => {
                    let nextX = p.x;
                    let nextY = p.y;

                    // Apply forces from wells
                    wells.forEach(well => {
                        const dx = well.x - p.x;
                        const dy = well.y - p.y;
                        const dist = Math.sqrt(dx * dx + dy * dy);
                        const force = (well.strength * p.mass) / (dist * dist + 10);

                        nextX += (dx / dist) * force;
                        nextY += (dy / dist) * force;
                    });

                    // Momentum (simulated)
                    nextY -= 0.5;

                    return { ...p, x: nextX, y: nextY };
                });

                // Check for captures
                updated = updated.filter(p => {
                    const captured = wells.find(w => {
                        const dist = Math.sqrt(Math.pow(w.x - p.x, 2) + Math.pow(w.y - p.y, 2));
                        return dist < 5;
                    });

                    if (captured) {
                        setScore(s => s + 500);
                        hapticSelection();
                        return false;
                    }

                    // Remove if out of bounds
                    return p.x > 0 && p.x < 100 && p.y > 0 && p.y < 100;
                });

                return updated;
            });
        }, 30);

        return () => clearInterval(interval);
    }, [gameState, wells]);

    const startGame = () => {
        initializeLevel();
        hapticSuccess();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[650px] bg-slate-950 rounded-[4rem] border border-white/10 overflow-hidden shadow-2xl flex flex-col font-mono">
            {/* 3D Grid & Space Layers */}
            <div className="absolute inset-0 z-0 overflow-hidden">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(56,189,248,0.15)_0%,transparent_80%)]" />
                <motion.div
                    className="absolute inset-0 opacity-10"
                    style={{
                        backgroundImage: "linear-gradient(#38bdf8 1px, transparent 1px), linear-gradient(90deg, #38bdf8 1px, transparent 1px)",
                        backgroundSize: "50px 50px",
                        perspective: "1000px",
                        rotateX: 60,
                        transformOrigin: "bottom"
                    }}
                    animate={{ backgroundPositionY: ["0px", "100px"] }}
                    transition={{ duration: 5, repeat: Infinity, ease: "linear" }}
                />
            </div>

            {/* UI: HUD Overlay */}
            <div className="relative z-20 p-10 flex justify-between items-start pointer-events-none">
                <div className="space-y-4">
                    <div className="bg-white/5 border border-white/10 p-5 rounded-[2rem] backdrop-blur-2xl">
                        <div className="flex items-center gap-3 mb-2">
                            <Layers className="text-sky-400 w-5 h-5" />
                            <h2 className="text-xl font-black italic tracking-tighter text-white">QUANTUM QUEST</h2>
                        </div>
                        <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.3em]">Singularity Stabilizer v9.1</p>
                    </div>

                    <div className="bg-sky-500/10 border border-sky-500/20 p-5 rounded-[2rem] backdrop-blur-xl">
                        <div className="flex justify-between items-end mb-2">
                            <span className="text-[10px] font-black text-sky-400 uppercase tracking-widest">Quantum Energy</span>
                            <span className="text-xl font-black italic">{energyLevel}%</span>
                        </div>
                        <div className="w-48 h-1.5 bg-white/5 rounded-full overflow-hidden">
                            <motion.div
                                className="h-full bg-sky-500 shadow-[0_0_15px_#0ea5e9]"
                                animate={{ width: `${energyLevel}%` }}
                            />
                        </div>
                    </div>
                </div>

                <div className="space-y-4">
                    <div className="bg-white/5 border border-white/10 p-5 rounded-[2rem] backdrop-blur-2xl min-w-[140px]">
                        <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Relativity Sync</p>
                        <p className="text-3xl font-black italic tracking-tighter tabular-nums">{score.toLocaleString()}</p>
                    </div>
                </div>
            </div>

            {/* Simulation Space */}
            <div className="relative z-10 flex-1 px-10 pb-10 flex flex-col items-center">
                <div className="relative w-full h-[350px] bg-slate-900/40 rounded-[3rem] border border-white/5 backdrop-blur-sm overflow-hidden border-sky-500/10">
                    {/* Gravity Wells */}
                    {wells.map(well => (
                        <div
                            key={well.id}
                            className="absolute -translate-x-1/2 -translate-y-1/2"
                            style={{ left: `${well.x}%`, top: `${well.y}%` }}
                        >
                            <motion.div
                                className="w-16 h-16 rounded-full border-2 border-dashed border-sky-500/40 flex items-center justify-center"
                                animate={{ rotate: 360 }}
                                transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
                            >
                                <div className="w-8 h-8 rounded-full bg-sky-400/20 flex items-center justify-center">
                                    <Target className="w-4 h-4 text-sky-400 opacity-60" />
                                </div>
                            </motion.div>
                            <div className="absolute top-full mt-2 left-1/2 -translate-x-1/2 text-center">
                                <span className="text-[8px] font-bold text-sky-500/60 uppercase tracking-widest leading-none">Singularity {well.id.split('-')[1]}</span>
                            </div>
                        </div>
                    ))}

                    {/* Particles */}
                    <AnimatePresence>
                        {particles.map(p => (
                            <motion.div
                                key={p.id}
                                className={`absolute w-3 h-3 rounded-full shadow-lg pointer-events-none
                                    ${p.type === 'electron' ? 'bg-rose-400 shadow-[0_0_10px_#fb7185]' :
                                        p.type === 'photon' ? 'bg-amber-400 shadow-[0_0_10px_#fbbf24]' :
                                            'bg-sky-400 shadow-[0_0_10px_#38bdf8]'}`}
                                style={{
                                    left: `${p.x}%`,
                                    top: `${p.y}%`,
                                    x: "-50%",
                                    y: "-50%"
                                }}
                            />
                        ))}
                    </AnimatePresence>

                    {/* Intro Overlay */}
                    {gameState === "IDLE" && (
                        <motion.div
                            {...JUICY_VARIANTS.slideUp}
                            className="absolute inset-0 z-40 bg-black/80 backdrop-blur-2xl flex flex-col items-center justify-center p-12 text-center"
                        >
                            <div className="bg-sky-500/20 p-6 rounded-[2.5rem] border border-sky-500/30 mb-8">
                                <Atom className="w-16 h-16 text-sky-400 animate-spin-slow" />
                            </div>
                            <h3 className="text-4xl font-black italic tracking-tighter text-white mb-4 uppercase">Quantum Linkage</h3>
                            <p className="text-zinc-400 text-sm max-w-sm mb-12">
                                Launch specialized particles into the gravity wells to stabilize the local quantum field. Don't let the energy core deplete!
                            </p>
                            <PhysicalButton onClick={startGame} className="bg-sky-500 h-20 px-16 rounded-[2.5rem] text-xl">
                                INITIALIZE REACTOR ⚛️
                            </PhysicalButton>
                        </motion.div>
                    )}
                </div>

                {/* Particle Launcher Controls */}
                <div className="mt-8 flex gap-6">
                    <div className="flex flex-col items-center gap-2">
                        <PhysicalButton
                            onClick={() => deployParticle('quark', 50, 80)}
                            className="w-24 h-24 rounded-3xl bg-sky-500/10 border border-sky-500/30 text-sky-400 hover:bg-sky-500/20"
                        >
                            <Cpu className="w-8 h-8" />
                        </PhysicalButton>
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">QUARK</span>
                    </div>

                    <div className="flex flex-col items-center gap-2">
                        <PhysicalButton
                            onClick={() => deployParticle('photon', 50, 80)}
                            className="w-24 h-24 rounded-3xl bg-amber-500/10 border border-amber-500/30 text-amber-400 hover:bg-amber-500/20"
                        >
                            <Zap className="w-8 h-8" />
                        </PhysicalButton>
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">PHOTON</span>
                    </div>

                    <div className="flex flex-col items-center gap-2">
                        <PhysicalButton
                            onClick={() => deployParticle('electron', 50, 80)}
                            className="w-24 h-24 rounded-3xl bg-rose-500/10 border border-rose-500/30 text-rose-400 hover:bg-rose-500/20"
                        >
                            <Maximize className="w-8 h-8" />
                        </PhysicalButton>
                        <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">ELECTRON</span>
                    </div>
                </div>
            </div>

            {/* Scanline / CRT Polish */}
            <div className="absolute inset-0 pointer-events-none z-50 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.05)_50%),linear-gradient(90deg,rgba(255,0,0,0.02),rgba(0,255,0,0.01),rgba(0,0,118,0.02))] bg-[length:100%_2px,3px_100%]" />
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { Zap, Cpu, Activity, ShieldCheck, Info, ChevronRight, Target, Atom, Sparkles, Binary, Layers, RotateCcw } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Quantum Logic Types --- */
type QubitState = "0" | "1" | "SUPERPOSITION" | "ENTANGLED";
type QuantumGate = "HADAMARD" | "CNOT" | "NOT" | "MEASURE";

interface Qubit {
    id: string;
    state: QubitState;
    entangledWith?: string;
}

export default function QuantumQuirk() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"IDLE" | "SOLVING" | "MEASURED" | "SUCCESS">("IDLE");
    const [qubits, setQubits] = useState<Qubit[]>([
        { id: "Q0", state: "0" },
        { id: "Q1", state: "0" }
    ]);
    const [history, setHistory] = useState<string[]>([]);

    const applyGate = (gate: QuantumGate, targetId: string) => {
        if (gameState !== "SOLVING") return;

        hapticSelection();
        setQubits(prev => prev.map(q => {
            if (q.id === targetId) {
                if (gate === "HADAMARD") {
                    return { ...q, state: "SUPERPOSITION" };
                }
                if (gate === "NOT") {
                    return { ...q, state: q.state === "0" ? "1" : "0" };
                }
                if (gate === "MEASURE") {
                    const collapsed = Math.random() > 0.5 ? "1" : "0";
                    return { ...q, state: collapsed as QubitState };
                }
            }
            return q;
        }));

        setHistory(prev => [...prev.slice(-4), gate]);
    };

    const handleCnot = (controlId: string, targetId: string) => {
        if (gameState !== "SOLVING") return;
        hapticSelection();

        const control = qubits.find(q => q.id === controlId);
        if (control?.state === "1") {
            applyGate("NOT", targetId);
        } else if (control?.state === "SUPERPOSITION") {
            setQubits(prev => prev.map(q => {
                if (q.id === targetId || q.id === controlId) {
                    return { ...q, state: "ENTANGLED", entangledWith: q.id === targetId ? controlId : targetId };
                }
                return q;
            }));
            setMessage("Quantum entanglement achieved! Spooky action at a distance detected. ⚛️");
        }
    };

    const checkSolution = () => {
        const measured = qubits.every(q => q.state === "0" || q.state === "1");
        if (measured) {
            setGameState("SUCCESS");
            hapticSuccess();
            setMessage("Algorithm stabilized. Quantum decoherence avoided! 🏆");
            setMood("happy");
        } else {
            hapticError();
            setMessage("State is still in flux. Collapse the wave function to confirm. 🌊");
        }
    };

    const startQuantumLab = () => {
        setGameState("SOLVING");
        setMood("thinking");
        setMessage("Welcome to the Subatomic Lab. Initialize the qubits and prepare for entanglement. ⚛️");
        hapticSelection();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[700px] bg-slate-950/20 rounded-[4rem] border border-cyan-500/20 overflow-hidden shadow-2xl flex flex-col font-sans text-white">
            {/* Cyberpunk Grid Background */}
            <div className="absolute inset-0 z-0">
                <div className="absolute inset-0 bg-[linear-gradient(to_right,#0891b210_1px,transparent_1px),linear-gradient(to_bottom,#0891b210_1px,transparent_1px)] bg-[size:40px_40px]" />
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(6,182,212,0.1)_0%,transparent_70%)]" />
            </div>

            {/* HUD Header */}
            <div className="relative z-20 p-8 flex justify-between items-center bg-black/40 backdrop-blur-2xl border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-2xl bg-cyan-500/10 border border-cyan-500/30 flex items-center justify-center">
                        <Atom className="text-cyan-400 w-8 h-8 animate-spin-slow" />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black italic tracking-tighter text-white uppercase leading-none">Quantum Quirk</h2>
                        <span className="text-[10px] font-bold text-cyan-600 uppercase tracking-widest">State Processor v2.0</span>
                    </div>
                </div>

                <div className="flex gap-6">
                    <StatusIndicator label="COHERENCE" value="98.2%" color="text-cyan-400" />
                    <StatusIndicator label="ENTROPY" value="Low" color="text-emerald-400" />
                    <div className="bg-white/5 border border-white/5 px-6 py-2 rounded-2xl">
                        <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest block mb-1">STABILITY</span>
                        <div className="flex gap-1">
                            {[1, 2, 3, 4, 5].map(i => (
                                <div key={i} className={`w-3 h-3 rounded-sm ${i < 4 ? 'bg-cyan-500' : 'bg-white/10'}`} />
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            {/* Main Lab Area */}
            <div className="relative z-10 flex-1 flex overflow-hidden">
                {/* Gate Library */}
                <div className="w-72 border-r border-white/5 p-8 flex flex-col gap-6 bg-black/20">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-2">Gate Library</h3>

                    <GateButton
                        label="Hadamard"
                        icon={Sparkles}
                        color="from-purple-500 to-indigo-600"
                        desc="Create Superposition"
                        onClick={() => applyGate("HADAMARD", "Q0")}
                    />
                    <GateButton
                        label="Pauli-X"
                        icon={Binary}
                        color="from-rose-500 to-orange-600"
                        desc="Flip Qubit State"
                        onClick={() => applyGate("NOT", "Q0")}
                    />
                    <GateButton
                        label="CNOT"
                        icon={Layers}
                        color="from-cyan-500 to-blue-600"
                        desc="Entangle Qubits"
                        onClick={() => handleCnot("Q0", "Q1")}
                    />
                    <GateButton
                        label="Measure"
                        icon={Activity}
                        color="from-emerald-500 to-teal-600"
                        desc="Collapse State"
                        onClick={() => applyGate("MEASURE", "Q0")}
                    />

                    <div className="mt-auto pt-6 border-t border-white/5 text-center">
                        <button
                            onClick={() => {
                                setQubits([{ id: "Q0", state: "0" }, { id: "Q1", state: "0" }]);
                                setHistory([]);
                                hapticSelection();
                            }}
                            className="text-[9px] font-black text-zinc-500 hover:text-white uppercase tracking-widest flex items-center justify-center gap-2 transition-colors mx-auto"
                        >
                            <RotateCcw className="w-3 h-3" /> Reset Circuit
                        </button>
                    </div>
                </div>

                {/* Quantum Circuit Visualizer */}
                <div className="flex-1 relative p-12 flex flex-col justify-center gap-16 overflow-hidden">
                    {/* Circuit Lines */}
                    <div className="absolute inset-0 flex flex-col justify-center gap-16 px-12 opacity-10 pointer-events-none">
                        <div className="h-0.5 w-full bg-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.5)]" />
                        <div className="h-0.5 w-full bg-cyan-400 shadow-[0_0_15px_rgba(6,182,212,0.5)]" />
                    </div>

                    {qubits.map((q, idx) => (
                        <div key={q.id} className="relative flex items-center gap-12 group">
                            <span className="text-sm font-black text-cyan-500/40 w-8">{q.id}</span>

                            <motion.div
                                layout
                                className={`relative w-40 h-40 rounded-[2.5rem] border-2 bg-black/60 backdrop-blur-3xl flex items-center justify-center overflow-hidden transition-all duration-500
                                ${q.state === "SUPERPOSITION" ? 'border-purple-500/50 shadow-[0_0_40px_rgba(168,85,247,0.2)]' :
                                        q.state === "ENTANGLED" ? 'border-cyan-500/50 shadow-[0_0_40px_rgba(6,182,212,0.2)]' :
                                            'border-white/5'}`}
                            >
                                <AnimatePresence mode="wait">
                                    <QubitVisual state={q.state} key={q.state} />
                                </AnimatePresence>

                                {/* Interference Patterns */}
                                {q.state === "SUPERPOSITION" && (
                                    <motion.div
                                        animate={{ opacity: [0.1, 0.3, 0.1], scale: [1, 1.2, 1] }}
                                        transition={{ duration: 2, repeat: Infinity }}
                                        className="absolute inset-0 bg-purple-500/10 blur-xl pointer-events-none"
                                    />
                                )}
                            </motion.div>

                            <div className="flex flex-col gap-1">
                                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">STATE</span>
                                <span className={`text-xl font-black italic italic uppercase ${q.state === "SUPERPOSITION" ? "text-purple-400" : q.state === "ENTANGLED" ? "text-cyan-400" : "text-white"}`}>
                                    {q.state}
                                </span>
                            </div>

                            {/* Entanglement Link */}
                            {q.entangledWith && idx === 0 && (
                                <motion.div
                                    initial={{ height: 0 }}
                                    animate={{ height: 128 }}
                                    className="absolute left-28 top-20 w-1 bg-gradient-to-bottom from-cyan-500 to-cyan-500/0 shadow-[0_0_20px_rgba(6,182,212,0.4)] z-0"
                                />
                            )}
