        );
    }

    if (state === "ENTANGLED") {
        return (
            <div className="flex gap-2">
                <motion.div
                    animate={{ scale: [1, 1.2, 1], opacity: [0.5, 1, 0.5] }}
                    transition={{ duration: 1.5, repeat: Infinity }}
