        problem: "60 + 4",
        answer: 64,
        x: 35,
        y: 35
    },
    {
        id: "sector_2",
        name: "Skyway Hub",
        description: "The transport tubes are offline. Solve the flow rate: 144 / 12.",
        problem: "144 ÷ 12",
        answer: 12,
        x: 65,
        y: 25
    },
    {
        id: "sector_3",
        name: "Cyber Tower",
