                <div className="p-2 bg-amber-500/20 rounded-xl border border-amber-500/30">
                    <Construction className="w-4 h-4 text-amber-400" />
                </div>
                <div className="flex flex-col">
                    <span className="text-[10px] text-white/40 font-bold uppercase tracking-widest">Protocol</span>
                    <span className="text-xs text-white font-medium">Spark-Quest City Eng.</span>
                </div>
            </div>

            <style jsx>{`
                .shake {
                    animation: shake-anim 0.4s cubic-bezier(.36,.07,.19,.97) both;
                }
                @keyframes shake-anim {
                    10%, 90% { transform: translate3d(-1px, 0, 0); }
                    20%, 80% { transform: translate3d(2px, 0, 0); }
                    30%, 50%, 70% { transform: translate3d(-4px, 0, 0); }
                    40%, 60% { transform: translate3d(4px, 0, 0); }
                }
            `}</style>
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { Navigation, Compass, Star, Map as MapIcon, Info, ChevronRight, Target, Move, Rocket, Sparkles, Crosshair, ZoomIn } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Star Steer Types --- */
type Constellation = "ORION" | "LYRA" | "CYGNUS" | "CASSIOPEIA";

interface StarData {
    id: string;
    name: string;
    constellation: Constellation;
    x: number;
    y: number;
    magnitude: number;
}

export default function StarSteer() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"IDLE" | "NAVIGATING" | "IDENTIFIED" | "SUCCESS">("IDLE");
    const [viewAngle, setViewAngle] = useState({ yaw: 0, pitch: 0 });
    const [targets, setTargets] = useState<string[]>([]);
    const [zoom, setZoom] = useState(1);

    const STARS: StarData[] = useMemo(() => [
        { id: "S1", name: "Rigel", constellation: "ORION", x: 25, y: 75, magnitude: 1.2 },
        { id: "S2", name: "Betelgeuse", constellation: "ORION", x: 30, y: 40, magnitude: 1.5 },
        { id: "S3", name: "Vega", constellation: "LYRA", x: 70, y: 30, magnitude: 1.1 },
        { id: "S4", name: "Deneb", constellation: "CYGNUS", x: 80, y: 50, magnitude: 1.3 },
        { id: "S5", name: "Cassiopeia A", constellation: "CASSIOPEIA", x: 15, y: 20, magnitude: 1.4 }
    ], []);

    const updateView = useCallback((dyaw: number, dpitch: number) => {
        if (gameState !== "NAVIGATING") return;
        setViewAngle(prev => ({
            yaw: (prev.yaw + dyaw + 360) % 360,
            pitch: Math.min(45, Math.max(-45, prev.pitch + dpitch))
        }));
        hapticSelection();
    }, [gameState]);

    const captureStar = (star: StarData) => {
        if (targets.includes(star.id)) return;
        setTargets(prev => [...prev, star.id]);
        hapticSuccess();
        setMessage(`Celestial body identified: ${star.name}. Coordinates logged to star-chart. 🌌`);
        setMood("happy");

        if (targets.length + 1 === STARS.length) {
            setGameState("SUCCESS");
            setMessage("Galaxy map complete! Galactic navigation established. 🚀");
        }
    };

    const startNav = () => {
        setGameState("NAVIGATING");
        setMood("thinking");
        setMessage("Engaging celestial sensors. Point the starship bridge toward identified constellations. 🚢");
        hapticSelection();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[700px] bg-slate-950/20 rounded-[4rem] border border-blue-500/20 overflow-hidden shadow-2xl flex flex-col font-sans text-white">
            {/* Deep Space Background */}
            <div className="absolute inset-0 z-0 bg-[radial-gradient(circle_at_center,rgba(30,58,138,0.2)_0%,transparent_80%)]">
                {/* 4K Starfield */}
                {Array.from({ length: 150 }).map((_, i) => (
                    <motion.div
                        key={i}
                        animate={{ opacity: [0.2, 0.8, 0.2] }}
                        transition={{ duration: 2 + Math.random() * 4, repeat: Infinity }}
                        className="absolute w-0.5 h-0.5 bg-white rounded-full"
                        style={{
                            left: `${Math.random() * 100}%`,
                            top: `${Math.random() * 100}%`,
                            transform: `scale(${Math.random()})`
                        }}
                    />
                ))}
            </div>

            {/* Bridge HUD Overlay */}
            <div className="relative z-20 p-8 flex justify-between items-center bg-zinc-900/60 backdrop-blur-2xl border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-2xl bg-blue-500/10 border border-blue-500/30 flex items-center justify-center">
                        <Rocket className="text-blue-400 w-8 h-8 group-hover:translate-y-[-4px] transition-transform" />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black italic tracking-tighter text-white uppercase leading-none text-blue-100">Star Steer</h2>
                        <span className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">Astro-Nav v9.4</span>
                    </div>
                </div>

                <div className="flex gap-6">
                    <HudValue label="YAW" value={`${viewAngle.yaw.toFixed(1)}°`} icon={Move} />
                    <HudValue label="PITCH" value={`${viewAngle.pitch.toFixed(1)}°`} icon={Navigation} />
                    <div className="bg-white/5 border border-white/5 px-6 py-2 rounded-2xl flex flex-col items-end">
                        <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest">MAGNIFICATION</span>
                        <span className="text-lg font-black italic text-blue-400 tabular-nums">{zoom.toFixed(1)}X</span>
                    </div>
                </div>
            </div>

            {/* Viewport & Controls */}
            <div className="relative z-10 flex-1 flex overflow-hidden">
                {/* Navigation Tools */}
                <div className="w-80 border-r border-white/5 p-8 flex flex-col gap-6 bg-zinc-900/40">
                    <h3 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-2 flex items-center gap-2">
                        <Compass className="w-3 h-3 text-blue-400" /> Sensor Controls
                    </h3>

                    <ControlPad
                        onMoveUp={() => updateView(0, 5)}
                        onMoveDown={() => updateView(0, -5)}
                        onMoveLeft={() => updateView(-5, 0)}
                        onMoveRight={() => updateView(5, 0)}
                    />

                    <div className="mt-8 flex flex-col gap-3">
                        <button
                            onClick={() => setZoom(prev => Math.min(4, prev + 0.5))}
                            className="bg-white/5 hover:bg-white/10 p-4 rounded-2xl flex items-center gap-4 border border-white/5 transition-colors"
                        >
                            <ZoomIn className="w-5 h-5 text-blue-400" />
                            <span className="text-[10px] font-black uppercase tracking-widest text-zinc-300">Magnify View</span>
                        </button>
                    </div>

                    <div className="mt-auto pt-8 border-t border-white/5">
                        <h4 className="text-[10px] font-black text-zinc-500 uppercase tracking-widest mb-4 italic">Star-Chart Catalog</h4>
                        <div className="grid grid-cols-2 gap-2">
                            {STARS.map(s => (
                                <div key={s.id} className={`p-2 rounded-xl border text-[8px] font-black text-center transition-all
                                    ${targets.includes(s.id) ? 'bg-blue-500/20 border-blue-500 text-blue-400' : 'bg-black/20 border-white/5 text-zinc-600'}`}>
                                    {s.name}
                                </div>
                            ))}
                        </div>
                    </div>
                </div>

                {/* The Celestial Sphere */}
                <div className="flex-1 relative bg-black/40 overflow-hidden">
                    {/* Crosshair Overlay */}
                    <div className="absolute inset-0 z-30 flex items-center justify-center pointer-events-none opacity-40">
                        <Crosshair className="w-24 h-24 text-blue-400/50" />
                        <div className="absolute w-64 h-64 border border-blue-400/20 rounded-full" />
                    </div>

                    {/* Viewport Content */}
                    <motion.div
                        animate={{
                            x: -viewAngle.yaw * 2,
                            y: viewAngle.pitch * 2,
                            scale: zoom
                        }}
                        transition={{ type: "spring", stiffness: 100 }}
                        className="absolute inset-0 w-[4000px] h-[2000px] -left-[1500px] -top-[650px]"
                    >
                        {STARS.map(star => (
                            <StarNode
                                key={star.id}
                                star={star}
                                isIdentified={targets.includes(star.id)}
                                onClick={() => captureStar(star)}
                            />
                        ))}
                    </motion.div>

                    {/* Scanning Grid */}
                    <div className="absolute inset-0 pointer-events-none opacity-20 bg-[linear-gradient(to_right,#3b82f615_1px,transparent_1px),linear-gradient(to_bottom,#3b82f615_1px,transparent_1px)] bg-[size:100px_100px]" />
                </div>
            </div>

            {/* Success Overlay */}
            <AnimatePresence>
                {gameState === "SUCCESS" && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        className="absolute inset-0 z-40 bg-zinc-950/80 backdrop-blur-3xl flex flex-col items-center justify-center p-12 text-center"
                    >
                        <div className="w-24 h-24 bg-blue-500/20 rounded-[2.5rem] flex items-center justify-center border border-blue-500/30 mb-8 overflow-hidden group shadow-[0_0_50px_rgba(59,130,246,0.3)]">
                            <Navigation className="w-12 h-12 text-blue-400 group-hover:rotate-45 transition-transform" />
                        </div>
                        <h3 className="text-6xl font-black italic tracking-tighter text-white mb-4 uppercase leading-none italic">Galaxy Mapped</h3>
                        <p className="text-zinc-500 text-sm max-w-sm mb-12 italic leading-relaxed">
                            Navigation stabilized. Celestial nodes synchronized. Starship trajectory optimized at 99.9% accuracy.
                        </p>
                        <PhysicalButton
                            onClick={() => window.location.reload()}
                            className="bg-blue-600 h-24 px-20 rounded-[3rem] text-2xl shadow-lg border border-blue-400/30"
                        >
                            RETURN TO HUB 🚀
                        </PhysicalButton>
                    </motion.div>
                )}
            </AnimatePresence>

            {/* Idle Overlay */}
            {gameState === "IDLE" && (
                <motion.div
                    {...JUICY_VARIANTS.slideUp}
                    className="absolute inset-0 z-40 bg-zinc-950/90 backdrop-blur-3xl flex flex-col items-center justify-center p-12 text-center"
                >
                    <div className="w-24 h-24 bg-blue-500/20 rounded-[2.5rem] flex items-center justify-center border border-blue-500/30 mb-8 overflow-hidden group">
                        <MapIcon className="w-12 h-12 text-blue-400 group-hover:scale-110 transition-transform duration-500" />
                    </div>
                    <h3 className="text-6xl font-black italic tracking-tighter text-white mb-4 uppercase leading-none italic">Star Steer</h3>
                    <p className="text-zinc-500 text-sm max-w-sm mb-12 italic leading-relaxed">
                        Journey through the final frontier. Navigate by the stars, identify constellations, and master spherical geometry in beautiful 4K.
                    </p>
                    <PhysicalButton
                        onClick={startNav}
                        className="bg-blue-600 h-24 px-20 rounded-[3rem] text-2xl shadow-lg border border-blue-400/30"
                    >
                        ENGAGE SYSTEMS 🚢
                    </PhysicalButton>
                </motion.div>
            )}
        </div>
    );
}

function HudValue({ label, value, icon: Icon }: { label: string, value: string, icon: any }) {
    return (
        <div className="flex flex-col items-end gap-1">
            <span className="text-[9px] font-black text-zinc-500 uppercase tracking-widest flex items-center gap-1">
                <Icon className="w-2.5 h-2.5" /> {label}
            </span>
            <span className="text-xl font-black italic text-white tabular-nums">{value}</span>
        </div>
    );
}

function ControlPad({ onMoveUp, onMoveDown, onMoveLeft, onMoveRight }: any) {
    return (
        <div className="grid grid-cols-3 gap-2 w-full max-w-[200px] mx-auto mb-4">
            <div />
            <ControlButton icon={ChevronRight} className="-rotate-90" onClick={onMoveUp} />
            <div />
            <ControlButton icon={ChevronRight} className="rotate-180" onClick={onMoveLeft} />
            <div className="w-12 h-12 rounded-xl bg-blue-500/10 border border-blue-500/20" />
            <ControlButton icon={ChevronRight} onClick={onMoveRight} />
            <div />
            <ControlButton icon={ChevronRight} className="rotate-90" onClick={onMoveDown} />
            <div />
        </div>
    );
}

function ControlButton({ icon: Icon, className, onClick }: any) {
    return (
        <button
            onClick={onClick}
            className={`w-12 h-12 rounded-xl bg-zinc-800 border border-white/5 flex items-center justify-center hover:bg-zinc-700 transition-colors flex-shrink-0 ${className}`}
        >
            <Icon className="w-5 h-5 text-blue-400" />
        </button>
    );
}

function StarNode({ star, isIdentified, onClick }: { star: StarData, isIdentified: boolean, onClick: () => void }) {
    return (
        <motion.button
            onClick={onClick}
            whileHover={{ scale: 1.2 }}
            className="absolute flex flex-col items-center gap-3 group"
            style={{ left: `${star.x}%`, top: `${star.y}%` }}
        >
            <div className="relative">
                <motion.div
                    animate={{ scale: [1, 1.2, 1], opacity: [0.6, 1, 0.6] }}
                    transition={{ duration: 2 + Math.random(), repeat: Infinity }}
                    className={`rounded-full shadow-[0_0_20px_rgba(255,255,255,0.4)]
                        ${star.magnitude < 1.3 ? 'w-4 h-4 bg-white' : 'w-3 h-3 bg-blue-100'}
                    `}
                />
                {!isIdentified && (
                    <div className="absolute inset-0 -m-4 border border-blue-400/30 rounded-full animate-pulse opacity-0 group-hover:opacity-100 transition-opacity" />
                )}
            </div>

            <AnimatePresence>
                {(isIdentified || true) && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.8 }}
                        animate={{ opacity: isIdentified ? 1 : 0.4, scale: 1 }}
                        className="bg-black/60 backdrop-blur-xl px-4 py-1.5 rounded-full border border-white/10"
                    >
                        <span className="text-[10px] font-black uppercase text-white tracking-widest whitespace-nowrap">
                            {star.name}
                        </span>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.button>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useRef, useCallback } from "react";
import { Cpu, Zap, Code, ShieldCheck, RefreshCw, Trophy } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Types --- */
type Point = { x: number; y: number };
type Direction = "UP" | "DOWN" | "LEFT" | "RIGHT";
type LogicNode = { id: string; x: number; y: number; type: "variable" | "loop" | "condition"; value: string };

const GRID_SIZE = 20;
const INITIAL_SPEED = 150;
const SPEED_INCREMENT = 5;

export default function SyntaxSerpent() {
    const { setMessage, setMood } = useMascot();
    const [snake, setSnake] = useState<Point[]>([{ x: 10, y: 10 }]);
    const [direction, setDirection] = useState<Direction>("RIGHT");
    const [nextDirection, setNextDirection] = useState<Direction>("RIGHT");
    const [nodes, setNodes] = useState<LogicNode[]>([]);
    const [score, setScore] = useState(0);
    const [gameState, setGameState] = useState<"IDLE" | "PLAYING" | "GAMEOVER">("IDLE");
    const [speed, setSpeed] = useState(INITIAL_SPEED);
    const [highScore, setHighScore] = useState(0);

    const gameLoopRef = useRef<NodeJS.Timeout | null>(null);

    // Logic Node Generation
    const spawnNode = useCallback((currentSnake: Point[]) => {
        const types: LogicNode["type"][] = ["variable", "loop", "condition"];
        const values = {
            variable: ["let x = 5", "const PI = 3.14", "var count = 0"],
            loop: ["for(i=0; i<n; i++)", "while(active)", "nodes.map()"],
            condition: ["if(x > 0)", "switch(state)", "isReady ? true : false"]
        };

        let newX: number = 0, newY: number = 0;
        let isOccupied = true;
        while (isOccupied) {
            newX = Math.floor(Math.random() * GRID_SIZE);
            newY = Math.floor(Math.random() * GRID_SIZE);
            isOccupied = currentSnake.some(s => s.x === newX && s.y === newY);
        }

        const type = types[Math.floor(Math.random() * types.length)];
        const newNode: LogicNode = {
            id: Math.random().toString(36).substr(2, 9),
            x: newX!,
            y: newY!,
            type,
            value: values[type][Math.floor(Math.random() * values[type].length)]
        };
        setNodes(prev => [...prev.slice(-2), newNode]); // Keep max 3 nodes on screen
    }, []);

    const startGame = () => {
        setSnake([{ x: 10, y: 10 }]);
        setDirection("RIGHT");
        setNextDirection("RIGHT");
        setScore(0);
        setSpeed(INITIAL_SPEED);
        setGameState("PLAYING");
        setNodes([]);
        spawnNode([{ x: 10, y: 10 }]);
        setMood("happy");
        setMessage("Let's build some high-speed logic! 🐍✨");
        hapticSuccess();
    };

    const endGame = () => {
        setGameState("GAMEOVER");
        setMood("sad");
        setMessage("Logic loop terminated. Let's try again!");
        hapticError();
        if (score > highScore) setHighScore(score);
    };

    const moveSnake = useCallback(() => {
        setSnake(prevSnake => {
            const head = prevSnake[0];
            const newHead = { ...head };

            setDirection(nextDirection);
            switch (nextDirection) {
                case "UP": newHead.y -= 1; break;
                case "DOWN": newHead.y += 1; break;
                case "LEFT": newHead.x -= 1; break;
                case "RIGHT": newHead.x += 1; break;
            }

            // Boundary Check
            if (newHead.x < 0 || newHead.x >= GRID_SIZE || newHead.y < 0 || newHead.y >= GRID_SIZE) {
                endGame();
                return prevSnake;
            }

            // Self Collision
            if (prevSnake.some(s => s.x === newHead.x && s.y === newHead.y)) {
                endGame();
                return prevSnake;
            }

            const newSnake = [newHead, ...prevSnake];

            // Node Collision
            const nodeIndex = nodes.findIndex(n => n.x === newHead.x && n.y === newHead.y);
            if (nodeIndex !== -1) {
                const node = nodes[nodeIndex];
                setScore(s => s + 100);
                setSpeed(v => Math.max(80, v - SPEED_INCREMENT));
                setNodes(prev => prev.filter((_, i) => i !== nodeIndex));
                spawnNode(newSnake);
                hapticSelection();
                setMood("happy");
                setMessage(`Great code! Collected: ${node.type}`);
            } else {
                newSnake.pop();
            }

            return newSnake;
        });
    }, [nextDirection, nodes, spawnNode]);

    useEffect(() => {
        if (gameState === "PLAYING") {
            gameLoopRef.current = setInterval(moveSnake, speed);
        } else {
            if (gameLoopRef.current) clearInterval(gameLoopRef.current);
        }
        return () => { if (gameLoopRef.current) clearInterval(gameLoopRef.current); };
    }, [gameState, speed, moveSnake]);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            switch (e.key) {
                case "ArrowUp": if (direction !== "DOWN") setNextDirection("UP"); break;
                case "ArrowDown": if (direction !== "UP") setNextDirection("DOWN"); break;
                case "ArrowLeft": if (direction !== "RIGHT") setNextDirection("LEFT"); break;
                case "ArrowRight": if (direction !== "LEFT") setNextDirection("RIGHT"); break;
            }
        };
        window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, [direction]);

    return (
        <div className="relative w-full max-w-4xl mx-auto aspect-square md:aspect-video bg-black rounded-[3rem] border border-white/10 overflow-hidden group shadow-2xl">
            {/* 4K Neon Grid Background */}
            <div className="absolute inset-0 z-0">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(56,189,248,0.1)_0%,transparent_70%)]" />
                <div className="absolute inset-0 opacity-20"
                    style={{
                        backgroundImage: "linear-gradient(#1e293b 1px, transparent 1px), linear-gradient(90deg, #1e293b 1px, transparent 1px)",
                        backgroundSize: `${100 / GRID_SIZE}% ${100 / GRID_SIZE}%`
                    }}
                />
                {/* Flowing Data Streams */}
                <div className="absolute inset-0 overflow-hidden pointer-events-none opacity-10">
                    {[...Array(5)].map((_, i) => (
                        <motion.div
                            key={i}
                            className="absolute bg-sky-500/20 blur-[1px]"
                            style={{
                                left: `${i * 25}%`,
                                width: '2px',
                                top: '-20%',
                                bottom: '-20%'
                            }}
                            animate={{ y: ["-100%", "100%"] }}
                            transition={{ duration: 5 + i, repeat: Infinity, ease: "linear" }}
                        />
                    ))}
                </div>
            </div>

            {/* Game Render Layer */}
            <div className="relative z-10 w-full h-full p-8 md:p-12 flex flex-col md:flex-row gap-8">
                {/* Left: Scoreboard */}
                <div className="flex flex-col justify-between md:w-48 space-y-6">
                    <div className="space-y-4">
                        <div className="bg-white/5 border border-white/10 p-4 rounded-3xl backdrop-blur-xl">
                            <p className="text-[10px] font-black uppercase text-sky-400 tracking-widest">Logic Score</p>
                            <p className="text-4xl font-black italic tracking-tighter tabular-nums">{score.toLocaleString()}</p>
                        </div>
                        <div className="bg-white/5 border border-white/10 p-4 rounded-3xl backdrop-blur-xl">
                            <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">High Score</p>
                            <p className="text-2xl font-black italic tracking-tighter text-zinc-400">{highScore.toLocaleString()}</p>
                        </div>
                    </div>

                    <div className="bg-sky-500/10 border border-sky-500/20 p-6 rounded-[2rem] backdrop-blur-md hidden md:block">
                        <div className="flex items-center gap-2 mb-4">
                            <Cpu className="text-sky-400 w-4 h-4" />
                            <h3 className="text-sm font-black italic">COMPILER STATUS</h3>
                        </div>
                        <div className="space-y-3">
                            <div className="h-1 bg-white/5 rounded-full overflow-hidden">
                                <motion.div
                                    className="h-full bg-sky-500 shadow-[0_0_10px_#0ea5e9]"
                                    animate={{ width: `${Math.min(100, (score / 5000) * 100)}%` }}
                                />
                            </div>
                            <p className="text-[9px] font-bold text-zinc-500 uppercase tracking-widest">Optimization: {Math.floor(speed / 2)}%</p>
                        </div>
                    </div>
                </div>

                {/* Center: The Grid */}
                <div className="flex-1 relative aspect-square bg-slate-900/50 rounded-[2.5rem] border border-white/10 backdrop-blur-sm overflow-hidden border-sky-500/20 shadow-[inset_0_0_50px_rgba(14,165,233,0.1)]">
                    {/* Snake Rendering */}
                    {snake.map((segment, i) => (
                        <motion.div
                            key={i}
                            layoutId={`snake-${i}`}
                            className={`absolute rounded-full z-20 ${i === 0 ? 'bg-sky-400 shadow-[0_0_15px_#38bdf8] z-30' : 'bg-sky-600/60'}`}
                            style={{
                                left: `${(segment.x / GRID_SIZE) * 100}%`,
                                top: `${(segment.y / GRID_SIZE) * 100}%`,
                                width: `${100 / GRID_SIZE}%`,
                                height: `${100 / GRID_SIZE}%`,
                            }}
                        />
                    ))}

                    {/* Nodes Rendering */}
                    <AnimatePresence>
                        {nodes.map(node => (
                            <motion.div
                                key={node.id}
                                initial={{ scale: 0, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                exit={{ scale: 0, opacity: 0 }}
                                className="absolute z-20 p-1"
                                style={{
                                    left: `${(node.x / GRID_SIZE) * 100}%`,
                                    top: `${(node.y / GRID_SIZE) * 100}%`,
                                    width: `${100 / GRID_SIZE}%`,
                                    height: `${100 / GRID_SIZE}%`,
                                }}
                            >
                                <div className={`w-full h-full rounded-lg border flex items-center justify-center shadow-lg
                                    ${node.type === 'variable' ? 'bg-emerald-500/20 border-emerald-500 animate-pulse' :
                                        node.type === 'loop' ? 'bg-amber-500/20 border-amber-500 animate-spin-slow' :
                                            'bg-indigo-500/20 border-indigo-500'}`}>
                                    {node.type === 'variable' ? <Code className="w-1/2 h-1/2 text-emerald-400" /> :
                                        node.type === 'loop' ? <RefreshCw className="w-1/2 h-1/2 text-amber-400" /> :
                                            <Zap className="w-1/2 h-1/2 text-indigo-400" />}
                                </div>
                                <div className="absolute top-full left-1/2 -translate-x-1/2 mt-1 whitespace-nowrap">
                                    <span className="text-[7px] font-black text-white/40 uppercase bg-black/50 px-1 rounded">{node.value}</span>
                                </div>
                            </motion.div>
                        ))}
                    </AnimatePresence>

                    {/* Overlays */}
                    <AnimatePresence>
                        {gameState === "IDLE" && (
                            <motion.div
                                {...JUICY_VARIANTS.slideUp}
                                className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-black/80 backdrop-blur-xl p-12 text-center"
                            >
                                <div className="bg-sky-500/20 p-6 rounded-[2.5rem] border border-sky-500/30 mb-8">
                                    <Code className="w-16 h-16 text-sky-400" />
                                </div>
                                <h2 className="text-4xl font-black italic tracking-tighter mb-4 text-white">SYNTAX SERPENT</h2>
                                <p className="text-zinc-400 text-sm font-medium mb-12 max-w-sm">
                                    Compile a logic chain by collecting high-value syntax nodes. Avoid boundary crashes and infinite loops!
                                </p>
                                <PhysicalButton
                                    onClick={startGame}
                                    className="bg-sky-500 h-20 px-16 rounded-[2rem] text-xl"
                                >
                                    INITIALIZE COMPILER ⚡
                                </PhysicalButton>
                            </motion.div>
                        )}

                        {gameState === "GAMEOVER" && (
                            <motion.div
                                {...JUICY_VARIANTS.slideUp}
                                className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-rose-950/90 backdrop-blur-2xl p-12 text-center"
                            >
                                <div className="bg-rose-500/20 p-6 rounded-[2.5rem] border border-rose-500/30 mb-8">
                                    <ShieldCheck className="w-16 h-16 text-rose-400" />
                                </div>
                                <h2 className="text-4xl font-black italic tracking-tighter mb-2 text-white">SYSTEM CRASH</h2>
                                <p className="text-rose-400 text-[10px] font-black uppercase tracking-[0.3em] mb-8">Memory Allocation Failure</p>

                                <div className="flex gap-4 mb-12">
                                    <div className="bg-white/5 p-4 rounded-3xl border border-white/10 min-w-[120px]">
                                        <p className="text-[8px] font-black uppercase text-zinc-500">Nodes Scanned</p>
                                        <p className="text-3xl font-black italic tracking-tighter">{score / 100}</p>
                                    </div>
                                    <div className="bg-white/5 p-4 rounded-3xl border border-white/10 min-w-[120px]">
                                        <p className="text-[8px] font-black uppercase text-zinc-500">Refined Skill</p>
                                        <p className="text-3xl font-black italic tracking-tighter text-sky-400">Logic++</p>
                                    </div>
                                </div>

                                <div className="flex gap-4">
                                    <PhysicalButton onClick={startGame} className="bg-white text-slate-950 h-16 px-10 rounded-2xl">
                                        REBOOT SESSION 🔄
                                    </PhysicalButton>
                                    <PhysicalButton onClick={() => setGameState("IDLE")} className="bg-white/10 h-16 px-10 rounded-2xl">
                                        QUIT ⏻
                                    </PhysicalButton>
                                </div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>

                {/* Right: Controls Hint */}
                <div className="hidden lg:flex flex-col items-center justify-center w-24 gap-4">
                    <div className="flex flex-col gap-2">
                        <div className="w-10 h-10 border border-white/20 rounded-xl flex items-center justify-center text-zinc-500">W</div>
                        <div className="flex gap-2">
                            <div className="w-10 h-10 border border-white/20 rounded-xl flex items-center justify-center text-zinc-500">A</div>
                            <div className="w-10 h-10 border border-white/20 rounded-xl flex items-center justify-center text-zinc-500">S</div>
                            <div className="w-10 h-10 border border-white/20 rounded-xl flex items-center justify-center text-zinc-500">D</div>
                        </div>
                    </div>
                    <span className="text-[8px] font-black text-zinc-600 uppercase tracking-widest leading-tight text-center">Use WASD or Arrows to steer</span>
                </div>
            </div>

            {/* Scanline Effect */}
            <div className="absolute inset-0 pointer-events-none z-40 bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.1)_50%),linear-gradient(90deg,rgba(255,0,0,0.03),rgba(0,255,0,0.01),rgba(0,0,118,0.03))] bg-[length:100%_2px,3px_100%]" />
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useMascot } from "@/components/experience/MascotHost";
import { JUICY_VARIANTS, JUICY_SPRINGS } from "@/lib/experience/interaction-primitives";
import PhysicalButton from "@/components/experience/PhysicalButton";
import JuicyStreak from "@/components/experience/JuicyStreak";
import JuicyConfetti from "@/components/experience/JuicyConfetti";
import { hapticSuccess, hapticCelebration, hapticSelection } from "@/lib/platform/haptics";
import { Beaker, Atom, Zap, Thermometer } from "lucide-react";

/* --- Synthesis Sphere Content --- */
type Element = {
    id: number;
    level: number; // 1: Hydrogen, 2: Helium, etc.
    name: string;
    symbol: string;
    color: string;
    glow: string;
};

const ELEMENTS: Record<number, Omit<Element, "id">> = {
    1: { level: 1, name: "Hydrogen", symbol: "H", color: "bg-sky-400", glow: "shadow-[0_0_20px_rgba(56,189,248,0.6)]" },
    2: { level: 2, name: "Helium", symbol: "He", color: "bg-amber-400", glow: "shadow-[0_0_25px_rgba(251,191,36,0.7)]" },
    3: { level: 3, name: "Lithium", symbol: "Li", color: "bg-rose-400", glow: "shadow-[0_0_30px_rgba(251,113,133,0.8)]" },
    4: { level: 4, name: "Beryllium", symbol: "Be", color: "bg-emerald-400", glow: "shadow-[0_0_35px_rgba(52,211,153,0.9)]" },
    5: { level: 5, name: "Boron", symbol: "B", color: "bg-indigo-400", glow: "shadow-[0_0_40px_rgba(129,140,248,1.0)]" },
};

export default function SynthesisSphere() {
    const { setMood, setMessage } = useMascot();
    const [grid, setGrid] = useState<(Element | null)[]>(Array(16).fill(null));
    const [score, setScore] = useState(0);
    const [streak, setStreak] = useState(0);
    const [showConfetti, setShowConfetti] = useState(false);

    useEffect(() => {
        setMessage("Welcome to the Synthesis Sphere. Merge elements to discover the secrets of the universe! 🔬✨");
        setMood("happy");
        spawnElement();
        spawnElement();
    }, []);

    const spawnElement = useCallback(() => {
        setGrid(prev => {
            const emptyIndices = prev.map((val, idx) => val === null ? idx : null).filter(val => val !== null) as number[];
            if (emptyIndices.length === 0) return prev;

            const randomIndex = emptyIndices[Math.floor(Math.random() * emptyIndices.length)];
            const newElement: Element = {
                id: Math.random(),
                ...ELEMENTS[1] // Always start with Hydrogen
            };

            const newGrid = [...prev];
            newGrid[randomIndex] = newElement;
            return newGrid;
        });
    }, []);

    const move = (direction: "up" | "down" | "left" | "right") => {
        let moved = false;
        let newScore = score;
        let mergedThisTurn = false;

        setGrid(prev => {
            const newGrid = [...prev];

            const getIndex = (row: number, col: number) => row * 4 + col;

            // Simplified 2048-style logic for a 4x4 grid
            const processLine = (line: (Element | null)[]) => {
                const filled = line.filter(x => x !== null) as Element[];
                const result: (Element | null)[] = [];

                for (let i = 0; i < filled.length; i++) {
                    if (filled[i] && filled[i + 1] && filled[i].level === filled[i + 1].level) {
                        const upgradedLevel = filled[i].level + 1;
                        if (ELEMENTS[upgradedLevel]) {
                            result.push({
                                id: Math.random(),
                                ...ELEMENTS[upgradedLevel]
                            });
                            newScore += upgradedLevel * 10;
                            mergedThisTurn = true;
                            i++; // Skip next
                            moved = true;
                        } else {
                            result.push(filled[i]);
                        }
                    } else {
                        result.push(filled[i]);
                    }
                }
                while (result.length < 4) result.push(null);
                return result;
            };

            // Horizontal Movement
            if (direction === "left" || direction === "right") {
                for (let r = 0; r < 4; r++) {
                    let row = [newGrid[getIndex(r, 0)], newGrid[getIndex(r, 1)], newGrid[getIndex(r, 2)], newGrid[getIndex(r, 3)]];
                    if (direction === "right") row.reverse();
                    const processed = processLine(row);
                    if (direction === "right") processed.reverse();

                    for (let c = 0; c < 4; c++) {
                        if (newGrid[getIndex(r, c)]?.id !== processed[c]?.id) moved = true;
                        newGrid[getIndex(r, c)] = processed[c];
                    }
                }
            }
            // Vertical Movement
            else {
                for (let c = 0; c < 4; c++) {
                    let col = [newGrid[getIndex(0, c)], newGrid[getIndex(1, c)], newGrid[getIndex(2, c)], newGrid[getIndex(3, c)]];
                    if (direction === "down") col.reverse();
                    const processed = processLine(col);
                    if (direction === "down") processed.reverse();

                    for (let r = 0; r < 4; r++) {
                        if (newGrid[getIndex(r, c)]?.id !== processed[r]?.id) moved = true;
                        newGrid[getIndex(r, c)] = processed[r];
                    }
                }
            }

            return newGrid;
        });

        if (moved) {
            spawnElement();
            setScore(newScore);
            void hapticSelection();
            if (mergedThisTurn) {
                setStreak(prev => prev + 1);
                void hapticSuccess();
                if (newScore % 100 === 0) {
                    setShowConfetti(true);
                    setTimeout(() => setShowConfetti(false), 2000);
                    void hapticCelebration();
                    setMood("happy");
                    setMessage("Synthesis complete! New heavy element discovered! 💎");
                }
            } else {
                setStreak(0);
            }
        }
    };

    // Keyboard listeners
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === "ArrowLeft") move("left");
            if (e.key === "ArrowRight") move("right");
            if (e.key === "ArrowUp") move("up");
            if (e.key === "ArrowDown") move("down");
        };
        window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, [grid]);

    return (
        <div className="relative min-h-[700px] w-full flex flex-col items-center justify-center p-8 bg-black overflow-hidden rounded-[3rem] border-4 border-slate-800 shadow-2xl">
            {/* 4K Background Image */}
            <div className="absolute inset-0 opacity-40">
                <img
                    src="/neural_synthesis_lab_bg_1772427420316.png"
                    alt="Synthesis Lab"
                    className="w-full h-full object-cover blur-sm"
                />
            </div>

            {/* Glass Overlays */}
            <div className="absolute inset-x-8 top-8 flex justify-between items-start z-10">
                <div className="flex flex-col">
                    <span className="text-xs font-black uppercase text-sky-400 tracking-[0.4em]">Subatomic Research</span>
                    <h2 className="text-5xl font-black italic text-white leading-none tracking-tighter">SYNTHESIS SPHERE</h2>
                </div>
                <div className="flex flex-col items-end gap-2">
                    <JuicyStreak count={streak} />
                    <div className="bg-white/5 border border-white/10 px-6 py-2 rounded-2xl backdrop-blur-xl">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block">Molecular Weight</span>
                        <span className="text-2xl font-black text-white">{score}u</span>
                    </div>
                </div>
            </div>

            <JuicyConfetti active={showConfetti} />

            {/* The Forge Grid */}
            <div className="relative z-10 grid grid-cols-4 gap-4 p-4 bg-white/5 border border-white/10 rounded-[2.5rem] backdrop-blur-2xl shadow-[0_0_100px_rgba(56,189,248,0.1)]">
                {grid.map((el, i) => (
                    <div key={i} className="w-20 h-20 rounded-2xl bg-black/40 border border-white/5 flex items-center justify-center overflow-hidden">
                        <AnimatePresence mode="popLayout">
                            {el && (
                                <motion.div
                                    key={el.id}
                                    layoutId={`el-${el.id}`}
                                    initial={{ scale: 0.8, opacity: 0 }}
                                    animate={{ scale: 1, opacity: 1 }}
                                    exit={{ scale: 1.2, opacity: 0 }}
                                    transition={JUICY_SPRINGS.bouncy}
                                    className={`w-16 h-16 rounded-full ${el.color} ${el.glow} flex flex-col items-center justify-center border-2 border-white/20`}
                                >
                                    <span className="text-2xl font-black text-white leading-none">{el.symbol}</span>
                                    <span className="text-[8px] font-black text-white/60 uppercase">{el.level}</span>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>
                ))}
            </div>

            {/* Controls Display */}
            <div className="mt-12 flex gap-8 z-10">
                <ControlIcon icon={Thermometer} label="Heat Sync" value="Optimal" color="text-rose-400" />
                <ControlIcon icon={Atom} label="Density" value="Stable" color="text-amber-400" />
                <ControlIcon icon={Zap} label="Pulse" value="Active" color="text-sky-400" />
            </div>

            {/* Mobile/Touch Controls */}
            <div className="mt-8 grid grid-cols-3 gap-2 md:hidden z-10">
                <div />
                <PhysicalButton onClick={() => move("up")} className="bg-white/5 h-12 w-12 rounded-xl">↑</PhysicalButton>
                <div />
                <PhysicalButton onClick={() => move("left")} className="bg-white/5 h-12 w-12 rounded-xl">←</PhysicalButton>
                <PhysicalButton onClick={() => move("down")} className="bg-white/5 h-12 w-12 rounded-xl">↓</PhysicalButton>
                <PhysicalButton onClick={() => move("right")} className="bg-white/5 h-12 w-12 rounded-xl">→</PhysicalButton>
            </div>

            {/* Terra's Log */}
            <div className="absolute bottom-8 right-8 flex items-center gap-4 bg-sky-950/40 border border-sky-500/20 px-6 py-3 rounded-2xl backdrop-blur-md z-10">
                <div className="flex -space-x-2">
                    {[1, 2, 3].map(i => <div key={i} className="w-2 h-2 rounded-full bg-sky-400 animate-pulse" style={{ animationDelay: `${i * 0.2}s` }} />)}
                </div>
                <span className="text-[10px] font-bold text-sky-200 uppercase tracking-widest px-2">Terra: Monitoring synthesis efficiency...</span>
            </div>
        </div>
    );
}

function ControlIcon({ icon: Icon, label, value, color }: { icon: any, label: string, value: string, color: string }) {
    return (
        <div className="flex items-center gap-3 bg-white/5 border border-white/5 px-4 py-2 rounded-2xl backdrop-blur-md">
            <Icon className={`${color} w-5 h-5`} />
            <div className="flex flex-col">
                <span className="text-[8px] font-black uppercase text-slate-500 tracking-wider">{label}</span>
                <span className="text-[10px] font-black text-white uppercase">{value}</span>
            </div>
        </div>
    );
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState, useEffect, useCallback, useMemo } from "react";
import { Globe, Mountain, Waves, Flame, Activity, ShieldCheck, Thermometer, Info, ChevronRight, Zap } from "lucide-react";
import { JUICY_SPRINGS, JUICY_VARIANTS } from "@/lib/experience/interaction-primitives";
import { hapticSelection, hapticSuccess, hapticError } from "@/lib/platform/haptics";
import PhysicalButton from "@/components/experience/PhysicalButton";
import { useMascot } from "@/components/experience/MascotHost";

/* --- Geology Types --- */
type Plate = {
    id: string;
    type: "OCEANIC" | "CONTINENTAL";
    pos: { x: number; y: number };
    vector: { x: number; y: number };
};

export default function TectonicTrek() {
    const { setMessage, setMood } = useMascot();
    const [gameState, setGameState] = useState<"IDLE" | "SIMULATING" | "EARTHQUAKE" | "STABLE">("IDLE");
    const [plates, setPlates] = useState<Plate[]>([
        { id: "p1", type: "CONTINENTAL", pos: { x: 30, y: 50 }, vector: { x: 0, y: 0 } },
        { id: "p2", type: "OCEANIC", pos: { x: 70, y: 50 }, vector: { x: 0, y: 0 } }
    ]);
    const [stats, setStats] = useState({
        tension: 0,
        elevation: 10,
        volcanic: 0
    });

    const updateSimulation = useCallback(() => {
        if (gameState !== "SIMULATING") return;

        setPlates(prev => {
            const next = prev.map(p => ({
                ...p,
                pos: {
                    x: Math.max(0, Math.min(100, p.pos.x + p.vector.x)),
                    y: Math.max(0, Math.min(100, p.pos.y + p.vector.y))
                }
            }));

            // Collision / Tension Logic
            const dist = Math.abs(next[0].pos.x - next[1].pos.x);
            if (dist < 10) {
                setStats(s => ({
                    ...s,
                    tension: Math.min(100, s.tension + 1),
                    elevation: s.elevation + 0.1,
                    volcanic: s.volcanic + 0.05
                }));
            } else {
                setStats(s => ({ ...s, tension: Math.max(0, s.tension - 0.5) }));
            }

            return next;
        });

    }, [gameState]);

    useEffect(() => {
        const interval = setInterval(updateSimulation, 100);
        return () => clearInterval(interval);
    }, [updateSimulation]);

    // Tension Release (Earthquake)
    useEffect(() => {
        if (stats.tension > 90) {
            setGameState("EARTHQUAKE");
            hapticError();
            setMood("surprised");
            setMessage("Tectonic tension reached critical limit! seismic event detected! 🌋");

            setTimeout(() => {
                setStats(s => ({ ...s, tension: 0, elevation: s.elevation + 5 }));
                setGameState("SIMULATING");
                setMood("happy");
                setMessage("Tension released. A new mountain range has formed. Nature's power is immense! 🏔️");
                hapticSuccess();
            }, 3000);
        }
    }, [stats.tension, setMood, setMessage]);

    const movePlate = (id: string, vx: number) => {
        setPlates(prev => prev.map(p => p.id === id ? { ...p, vector: { ...p.vector, x: vx } } : p));
        hapticSelection();
    };

    const startSim = () => {
        setGameState("SIMULATING");
        setMood("thinking");
        setMessage("Tectonic plates initialized. Guide the lithospheric movement to shape the planet! 🌍");
        hapticSuccess();
    };

    return (
        <div className="relative w-full max-w-5xl mx-auto h-[650px] bg-slate-950 rounded-[4rem] border border-orange-500/20 overflow-hidden shadow-2xl flex flex-col font-sans">
            {/* Topographic Background */}
            <div className="absolute inset-0 z-0 opacity-20 pointer-events-none">
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(249,115,22,0.1)_0%,transparent_70%)]" />
                {/* SVG Contours */}
                <svg className="absolute inset-0 w-full h-full text-orange-500/5">
                    <defs>
                        <pattern id="contour" x="0" y="0" width="100" height="100" patternUnits="userSpaceOnUse">
                            <circle cx="50" cy="50" r="40" fill="none" stroke="currentColor" strokeWidth="0.5" />
                            <circle cx="50" cy="50" r="30" fill="none" stroke="currentColor" strokeWidth="0.5" />
                        </pattern>
                    </defs>
                    <rect width="100%" height="100%" fill="url(#contour)" />
                </svg>
            </div>

            {/* HUD */}
            <div className="relative z-20 p-8 flex justify-between items-center bg-zinc-900/60 backdrop-blur-2xl border-b border-white/5">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 rounded-2xl bg-orange-500/10 border border-orange-500/30 flex items-center justify-center">
                        <Mountain className="text-orange-400 w-8 h-8" />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black italic tracking-tighter text-white uppercase leading-none">Tectonic Trek</h2>
                        <span className="text-[10px] font-bold text-orange-600 uppercase tracking-widest">Lithosphere Sim v4.2</span>
                    </div>
                </div>

                <div className="flex gap-6">
                    <StatBox label="Seismic Tension" value={stats.tension} color="text-rose-400" />
                    <StatBox label="Mean Elevation" value={stats.elevation} color="text-sky-400" unit="km" />
                    <StatBox label="Volcanic Activity" value={stats.volcanic} color="text-orange-400" />
                </div>
            </div>

            {/* Main Area: Crust Simulation */}
            <div className={`relative z-10 flex-1 p-10 flex flex-col items-center justify-center transition-all duration-300 ${gameState === "EARTHQUAKE" ? 'shake-animation' : ''}`}>

                {/* Visualizer: The Earth's Crust */}
                <div className="relative w-full max-w-3xl h-64 bg-zinc-900/40 rounded-[3rem] border border-white/5 overflow-hidden flex items-end">
                    {/* Mantle Glow */}
                    <div className="absolute inset-x-0 bottom-0 h-2 bg-gradient-to-t from-orange-600/50 to-transparent" />

                    {/* The Plates */}
                    {plates.map(plate => (
                        <motion.div
                            key={plate.id}
                            className={`absolute bottom-4 h-32 rounded-2xl flex flex-col items-center justify-center border-t-4 shadow-2xl
                                ${plate.type === "CONTINENTAL" ? 'w-48 bg-stone-700 border-stone-500' : 'w-64 bg-slate-800 border-slate-600'}`}
                            animate={{ left: `${plate.pos.x}%` }}
                            transition={{ type: "spring", stiffness: 50 }}
                            style={{ x: "-50%" }}
                        >
                            <span className="text-[10px] font-black uppercase tracking-widest text-white/20 mb-2">{plate.type}</span>
                            {plate.type === "CONTINENTAL" ? <Mountain className="w-8 h-8 text-white/10" /> : <Waves className="w-8 h-8 text-white/10" />}
                        </motion.div>
                    ))}

                    {/* Collision Glow */}
                    {Math.abs(plates[0].pos.x - plates[1].pos.x) < 15 && (
                        <motion.div
                            className="absolute bottom-0 left-1/2 -translate-x-1/2 w-32 h-32 bg-orange-500/20 blur-[60px]"
                            animate={{ opacity: [0.2, 0.5, 0.2] }}
                            transition={{ duration: 1, repeat: Infinity }}
                        />
                    )}
                </div>

                {/* Controls */}
                {gameState === "SIMULATING" && (
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="mt-12 flex gap-12"
                    >
                        <PlateControl label="North American Plate" onMove={(v) => movePlate("p1", v)} />
                        <PlateControl label="Pacific Plate" onMove={(v) => movePlate("p2", v)} />
                    </motion.div>
